insert into public.vocabulary_words
  (id, language_code, word, definition, example_sentence, cefr_level, category, synonyms, usage)
values
('b1-001', 'es', 'desarrollar', 'to develop, to expand', 'La empresa quiere desarrollar nuevos productos este año.', 'B1'::cefr_level, 'Business', ARRAY['ampliar','crear'], '{"note":"To develop or build up (products, skills, ideas, a plot); reflexive desarrollarse = to take place/grow. ampliar is more ''widen''.","examples":["El país desarrolló su industria en pocas décadas."],"collocations":["desarrollar un proyecto","desarrollar una habilidad"]}'::jsonb),
('b1-002', 'es', 'conseguir', 'to get, to manage to achieve', 'Por fin conseguí un trabajo en el extranjero.', 'B1'::cefr_level, 'Daily Life', ARRAY['lograr','obtener'], '{"grammar":"irregular e→i: consigo, consiguió","note":"To get / succeed in getting; ''conseguir + inf.'' = to manage to. lograr is close; obtener is more formal ''obtain''.","examples":["Con esfuerzo conseguirás lo que te propones."],"collocations":["conseguir un trabajo","conseguir algo"]}'::jsonb),
('b1-003', 'es', 'mejorar', 'to improve', 'Quiero mejorar mi pronunciación en español.', 'B1'::cefr_level, 'Education', ARRAY['perfeccionar'], '{"note":"To improve — something, or (intransitive) to get better (health, weather). perfeccionar = to polish to near-perfect.","examples":["Su español mejoró muchísimo tras el curso."],"collocations":["mejorar la calidad","mejorar notablemente"]}'::jsonb),
('b1-004', 'es', 'ahorrar', 'to save (money or time)', 'Intento ahorrar un poco de dinero cada mes.', 'B1'::cefr_level, 'Finance', ARRAY['economizar'], '{"note":"To save money, time or effort (put aside / not waste). NOT ''save'' as in rescue (that''s salvar) or save a file (guardar).","examples":["Ahorró lo suficiente para comprar un piso."],"collocations":["ahorrar dinero","ahorrar tiempo"]}'::jsonb),
('b1-005', 'es', 'gastar', 'to spend', 'No quiero gastar mucho dinero este fin de semana.', 'B1'::cefr_level, 'Finance', ARRAY['malgastar'], '{"note":"To spend money, or use up/wear out (gastar pilas, gastar zapatos). For spending time use pasar. malgastar = to waste.","examples":["Gastó todos sus ahorros en el coche."],"collocations":["gastar dinero","gastar una broma"]}'::jsonb),
('b1-006', 'es', 'prestar', 'to lend', '¿Me puedes prestar tu cargador un momento?', 'B1'::cefr_level, 'Daily Life', ARRAY['dejar'], '{"note":"To lend (give temporarily). The reverse — to borrow — is ''pedir prestado''. Also ''prestar atención'' = to pay attention.","examples":["Le presté mi paraguas y no me lo devolvió."],"collocations":["prestar dinero","prestar atención","pedir prestado"]}'::jsonb),
('b1-007', 'es', 'devolver', 'to return (something)', 'Tengo que devolver estos libros a la biblioteca.', 'B1'::cefr_level, 'Daily Life', ARRAY['restituir'], '{"grammar":"irregular o→ue: devuelvo","note":"To give something back (goods, money, a favour). For coming back yourself use volver/regresar, not devolver.","examples":["Ya devolví los libros a la biblioteca."],"collocations":["devolver el dinero","devolver una llamada"]}'::jsonb),
('b1-008', 'es', 'reservar', 'to book, to reserve', 'Voy a reservar una mesa para cuatro personas.', 'B1'::cefr_level, 'Travel', ARRAY['apartar'], '{"note":"To book/reserve (table, room, ticket) or set aside for later. Noun: reserva (booking).","examples":["Reservé una habitación con vistas al mar."],"collocations":["reservar una mesa","reservar un hotel"]}'::jsonb),
('b1-009', 'es', 'alojarse', 'to stay, to lodge', 'Nos vamos a alojar en un hotel cerca de la playa.', 'B1'::cefr_level, 'Travel', ARRAY['hospedarse'], '{"grammar":"reflexive","note":"To stay/lodge somewhere as a guest; hospedarse is a close synonym. For remaining/staying put use quedarse.","examples":["Se alojaron en una casa rural encantadora."],"collocations":["alojarse en un hotel","alojarse en casa de alguien"]}'::jsonb),
('b1-010', 'es', 'recorrer', 'to travel through, to cover (distance)', 'Queremos recorrer toda la costa en coche.', 'B1'::cefr_level, 'Travel', ARRAY['atravesar'], '{"note":"To travel over/around an area or cover a distance; atravesar = to cross straight through. Noun: recorrido (route).","examples":["Recorrimos el país entero en autobús."],"collocations":["recorrer un camino","recorrer una distancia"]}'::jsonb),
('b1-011', 'es', 'aprovechar', 'to take advantage of, to make the most of', 'Hay que aprovechar el buen tiempo para salir.', 'B1'::cefr_level, 'Daily Life', ARRAY['explotar'], '{"note":"To make the most of an opportunity (positive); reflexive ''aprovecharse de'' = to exploit unfairly (negative). ''¡Que aproveche!'' = enjoy your meal.","examples":["Aproveché el descuento para renovar el móvil."],"collocations":["aprovechar la ocasión","aprovecharse de alguien"]}'::jsonb),
('b1-012', 'es', 'quedar', 'to arrange to meet; to remain', 'Quedamos a las ocho delante del cine.', 'B1'::cefr_level, 'Daily Life', ARRAY['citarse'], '{"note":"Many uses: ''quedar con alguien'' = arrange to meet; ''quedar'' = to be left/remain; ''quedarse'' = to stay; ''quedar bien/mal'' = to look good/bad.","examples":["Me quedé en casa todo el fin de semana."],"collocations":["quedar con alguien","quedarse en casa","quedar bien"]}'::jsonb),
('b1-013', 'es', 'soler', 'to usually do something', 'Suelo desayunar café con tostadas.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"grammar":"irregular o→ue; only + infinitive","note":"''soler + infinitive'' = to usually/tend to do something — there''s no single English verb; translate with ''usually''. Only in present & imperfect.","examples":["De pequeños solíamos veranear en el pueblo."],"collocations":["suelo hacer","solía ir"]}'::jsonb),
('b1-014', 'es', 'tardar', 'to take time, to be late', 'El tren tarda dos horas en llegar a la ciudad.', 'B1'::cefr_level, 'Travel', ARRAY['demorar'], '{"note":"''tardar + time + en + inf.'' = to take (that long) to do; also to be late/slow. Don''t confuse with tarde (afternoon/late).","examples":["Tardé una hora en encontrar aparcamiento."],"collocations":["tardar en llegar","tardar mucho"]}'::jsonb),
('b1-015', 'es', 'apuntar', 'to note down; to sign up', 'Voy a apuntar la dirección en mi teléfono.', 'B1'::cefr_level, 'Education', ARRAY['anotar'], '{"note":"To jot down; also to point at, and reflexive ''apuntarse a'' = to sign up for. anotar is the plain ''note down''.","examples":["Apunté su número en una servilleta."],"collocations":["apuntar una dirección","apuntarse a un curso"]}'::jsonb),
('b1-016', 'es', 'entregar', 'to hand in, to deliver', 'Debo entregar el trabajo antes del viernes.', 'B1'::cefr_level, 'Education', ARRAY['presentar'], '{"note":"To hand over/in (homework, a package, a prize); reflexive ''entregarse a'' = to devote oneself / surrender. presentar = to present/submit.","examples":["Entregó el trabajo justo a tiempo."],"collocations":["entregar un trabajo","entregar un premio"]}'::jsonb),
('b1-017', 'es', 'aprobar', 'to pass (an exam); to approve', 'Estudié mucho para aprobar el examen de historia.', 'B1'::cefr_level, 'Education', ARRAY['pasar'], '{"grammar":"irregular o→ue: apruebo","note":"To pass an exam/subject, or to approve (a law, plan). Opposite of suspender. Note: ''aprobar'', not ''pasar'', for exams.","examples":["Aprobó todas las asignaturas en junio."],"collocations":["aprobar un examen","aprobar una ley"]}'::jsonb),
('b1-018', 'es', 'suspender', 'to fail (an exam); to suspend', 'No quiero suspender ninguna asignatura este curso.', 'B1'::cefr_level, 'Education', ARRAY['reprobar'], '{"note":"To fail an exam (Spain), or to suspend/call off (an event, someone). Opposite of aprobar. In Latin America ''reprobar'' is common for failing.","examples":["Suspendió el examen de conducir dos veces."],"collocations":["suspender un examen","suspender un partido"]}'::jsonb),
('b1-019', 'es', 'matricularse', 'to enroll, to register', 'Me voy a matricular en un curso de italiano.', 'B1'::cefr_level, 'Education', ARRAY['inscribirse'], '{"grammar":"reflexive; + en","note":"To enrol in a course/school; inscribirse is close (also for events). Noun: matrícula (enrolment; also number plate).","examples":["Se matriculó en la universidad este año."],"collocations":["matricularse en un curso","matricularse en la universidad"]}'::jsonb),
('b1-020', 'es', 'asignatura', 'school subject', 'Mi asignatura favorita siempre fue la geografía.', 'B1'::cefr_level, 'Education', ARRAY['materia'], '{"grammar":"f.","note":"A school/university subject; materia is a close synonym. ''asignatura pendiente'' = an unresolved matter (idiom).","collocations":["una asignatura optativa","asignatura pendiente"]}'::jsonb),
('b1-021', 'es', 'horario', 'schedule, timetable', 'El horario de la biblioteca cambia en verano.', 'B1'::cefr_level, 'Daily Life', ARRAY['agenda'], '{"grammar":"m.","note":"A timetable/opening hours; ''horario laboral'' = working hours. agenda is your personal planner/diary.","collocations":["horario laboral","horario de apertura"]}'::jsonb),
('b1-022', 'es', 'reunión', 'meeting', 'Tenemos una reunión importante el lunes por la mañana.', 'B1'::cefr_level, 'Business', ARRAY['junta'], '{"grammar":"f.","note":"A meeting or gathering; junta is more a formal board meeting. Verb: reunirse (to meet up).","collocations":["una reunión de trabajo","convocar una reunión"]}'::jsonb),
('b1-023', 'es', 'empresa', 'company, firm', 'Trabaja en una empresa de tecnología desde hace años.', 'B1'::cefr_level, 'Business', ARRAY['compañía'], '{"grammar":"f.","note":"A company/firm (also ''an undertaking''); compañía is a near-synonym. Person who runs one: empresario/a.","collocations":["una empresa privada","montar una empresa"]}'::jsonb),
('b1-024', 'es', 'sueldo', 'salary, wage', 'Su nuevo sueldo le permite ahorrar más.', 'B1'::cefr_level, 'Finance', ARRAY['salario'], '{"grammar":"m.","note":"Regular pay/salary; salario is the more formal/legal term. ''sueldo mínimo'' = minimum wage.","collocations":["cobrar un sueldo","un buen sueldo"]}'::jsonb),
('b1-025', 'es', 'factura', 'bill, invoice', 'Aún no he pagado la factura de la luz.', 'B1'::cefr_level, 'Finance', ARRAY['recibo'], '{"grammar":"f.","note":"An invoice/utility bill; recibo is more a receipt/proof of payment. A restaurant bill is ''la cuenta''.","collocations":["pagar una factura","la factura de la luz"]}'::jsonb),
('b1-026', 'es', 'cuenta', 'account; bill', 'Abrí una cuenta nueva en el banco esta semana.', 'B1'::cefr_level, 'Finance', ARRAY[]::text[], '{"grammar":"f.","note":"Bank account, or the bill (in a restaurant). Key idiom: ''darse cuenta de'' = to realise; ''tener en cuenta'' = to bear in mind.","collocations":["una cuenta bancaria","darse cuenta de","pedir la cuenta"]}'::jsonb),
('b1-027', 'es', 'presupuesto', 'budget; estimate', 'Tenemos un presupuesto limitado para el viaje.', 'B1'::cefr_level, 'Finance', ARRAY['estimación'], '{"grammar":"m.","note":"A budget, or a price estimate/quote (e.g. from a builder). ''pedir un presupuesto'' = to ask for a quote.","collocations":["un presupuesto ajustado","pedir un presupuesto"]}'::jsonb),
('b1-028', 'es', 'barato', 'cheap, inexpensive', 'Encontramos un vuelo muy barato a Lisboa.', 'B1'::cefr_level, 'Finance', ARRAY['económico'], '{"note":"Cheap/inexpensive; económico is a softer ''affordable''. Opposite of caro. ''lo barato sale caro'' = buy cheap, pay twice.","collocations":["muy barato","salir barato"]}'::jsonb),
('b1-029', 'es', 'caro', 'expensive', 'Ese restaurante es demasiado caro para mí.', 'B1'::cefr_level, 'Finance', ARRAY['costoso'], '{"note":"Expensive; costoso is more formal. Opposite of barato. Also adverb: ''costar caro'' = to cost dearly.","collocations":["demasiado caro","costar caro"]}'::jsonb),
('b1-030', 'es', 'gratis', 'free of charge', 'La entrada al museo es gratis los domingos.', 'B1'::cefr_level, 'Daily Life', ARRAY['gratuito'], '{"grammar":"invariable","note":"Free of charge; invariable (never *gratises*). gratuito/a is the adjective that agrees. Not ''free'' as in libre (unrestricted).","collocations":["entrada gratis","totalmente gratis"]}'::jsonb),
('b1-031', 'es', 'descuento', 'discount', 'Me hicieron un descuento del veinte por ciento.', 'B1'::cefr_level, 'Finance', ARRAY['rebaja'], '{"grammar":"m.","note":"A discount; rebaja is more a sale/markdown (las rebajas = the sales). ''hacer un descuento'' = to give a discount.","collocations":["hacer un descuento","un descuento del 20%"]}'::jsonb),
('b1-032', 'es', 'ganga', 'bargain', 'Estos zapatos fueron una auténtica ganga.', 'B1'::cefr_level, 'Finance', ARRAY['chollo'], '{"grammar":"f.","note":"A bargain — something great for very little money; chollo is the colloquial equivalent. ''¡Es una ganga!''.","collocations":["una auténtica ganga","conseguir una ganga"]}'::jsonb),
('b1-033', 'es', 'moneda', 'coin; currency', 'Necesito una moneda para el carrito del supermercado.', 'B1'::cefr_level, 'Finance', ARRAY['divisa'], '{"grammar":"f.","note":"A coin, or a currency (la moneda única = the single currency). divisa is ''foreign currency'' in finance.","collocations":["una moneda de euro","la moneda nacional"]}'::jsonb),
('b1-034', 'es', 'paisaje', 'landscape, scenery', 'El paisaje de las montañas era impresionante.', 'B1'::cefr_level, 'Travel', ARRAY['panorama'], '{"grammar":"m. (despite -e it''s masculine)","note":"Landscape/scenery; also a genre in art (un paisaje = a landscape painting). panorama = a sweeping view.","collocations":["un paisaje impresionante","un paisaje urbano"]}'::jsonb),
('b1-035', 'es', 'frontera', 'border', 'Cruzamos la frontera sin ningún problema.', 'B1'::cefr_level, 'Travel', ARRAY['límite'], '{"grammar":"f.","note":"A national border; also figurative limits (las fronteras del conocimiento). Adjective: fronterizo.","collocations":["cruzar la frontera","la frontera con Francia"]}'::jsonb),
('b1-036', 'es', 'equipaje', 'luggage', 'Perdí el equipaje en el aeropuerto.', 'B1'::cefr_level, 'Travel', ARRAY['maletas'], '{"grammar":"m., uncountable","note":"Luggage as a whole (uncountable, like English); ''equipaje de mano'' = hand luggage. For individual bags: maletas.","collocations":["equipaje de mano","facturar el equipaje"]}'::jsonb),
('b1-037', 'es', 'retraso', 'delay', 'El vuelo salió con dos horas de retraso.', 'B1'::cefr_level, 'Travel', ARRAY['demora'], '{"grammar":"m.","note":"A delay/lateness; ''con retraso'' = late, ''llevar retraso'' = to be running behind. demora is a close synonym.","collocations":["con retraso","un retraso de dos horas"]}'::jsonb),
('b1-038', 'es', 'alojamiento', 'accommodation', 'Buscamos alojamiento barato cerca del centro.', 'B1'::cefr_level, 'Travel', ARRAY['hospedaje'], '{"grammar":"m.","note":"Accommodation/lodging (uncountable); the noun of alojarse. hospedaje is a close synonym.","collocations":["buscar alojamiento","alojamiento y desayuno"]}'::jsonb),
('b1-039', 'es', 'itinerario', 'itinerary, route', 'Preparé un itinerario completo para el viaje.', 'B1'::cefr_level, 'Travel', ARRAY['recorrido'], '{"grammar":"m.","note":"A planned itinerary/route; recorrido is the route actually travelled. ''seguir un itinerario''.","collocations":["preparar un itinerario","un itinerario turístico"]}'::jsonb),
('b1-040', 'es', 'costumbre', 'custom, habit', 'Probar la comida local es una buena costumbre.', 'B1'::cefr_level, 'Culture', ARRAY['hábito'], '{"grammar":"f.","note":"A custom (shared) or personal habit; ''como de costumbre'' = as usual; ''tener la costumbre de'' = to be in the habit of.","collocations":["como de costumbre","una vieja costumbre"]}'::jsonb),
('b1-041', 'es', 'tradición', 'tradition', 'La tradición de la siesta sigue viva en algunos pueblos.', 'B1'::cefr_level, 'Culture', ARRAY['usanza'], '{"grammar":"f.","note":"A tradition; ''por tradición'' = traditionally. Adjective: tradicional. usanza is more literary (''a la antigua usanza'').","collocations":["una tradición popular","mantener la tradición"]}'::jsonb),
('b1-042', 'es', 'fiesta', 'party; festival; public holiday', 'La fiesta del pueblo dura toda la semana.', 'B1'::cefr_level, 'Culture', ARRAY['celebración'], '{"grammar":"f.","note":"A party, a town festival, or a public holiday (''mañana es fiesta'' = tomorrow''s a holiday). ''las fiestas'' = the festivities.","collocations":["una fiesta de cumpleaños","día de fiesta"]}'::jsonb),
('b1-043', 'es', 'receta', 'recipe; prescription', 'Mi abuela me dio la receta de la paella.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"grammar":"f.","note":"A cooking recipe, or a medical prescription — context decides. For the medical sense you''ll also see ''receta médica''.","collocations":["la receta de la paella","una receta médica"]}'::jsonb),
('b1-044', 'es', 'ingrediente', 'ingredient', 'Falta un ingrediente para terminar el postre.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"grammar":"m. (despite -e it''s masculine)","note":"An ingredient (cooking, or figuratively of success). ''los ingredientes de una receta''.","collocations":["los ingredientes de una receta","un ingrediente clave"]}'::jsonb),
('b1-045', 'es', 'saludable', 'healthy (food, lifestyle)', 'Intento llevar una dieta más saludable.', 'B1'::cefr_level, 'Health', ARRAY['sano'], '{"note":"Healthy/health-giving — of food, habits, lifestyle. sano can describe a person''s health too; saludable is what''s good for you.","collocations":["una dieta saludable","un estilo de vida saludable"]}'::jsonb),
('b1-046', 'es', 'enfermedad', 'illness, disease', 'Es una enfermedad común pero fácil de tratar.', 'B1'::cefr_level, 'Health', ARRAY['dolencia'], '{"grammar":"f.","note":"Illness or disease in general; dolencia is a milder ailment/complaint. Person who is ill: enfermo.","collocations":["una enfermedad grave","prevenir enfermedades"]}'::jsonb),
('b1-047', 'es', 'receta médica', 'medical prescription', 'Necesito una receta médica para este medicamento.', 'B1'::cefr_level, 'Health', ARRAY[]::text[], '{"grammar":"f.","note":"A doctor''s prescription (the specific sense of receta); ''con receta'' = prescription-only, ''sin receta'' = over the counter.","collocations":["con receta médica","sin receta"]}'::jsonb),
('b1-048', 'es', 'cita', 'appointment; date; quotation', 'Tengo cita con el dentista el jueves.', 'B1'::cefr_level, 'Health', ARRAY['turno'], '{"grammar":"f.","note":"An appointment or a romantic date; also a quotation (in a text). ''pedir cita'' = to make an appointment. In parts of L.America ''turno''.","collocations":["pedir cita","una cita médica","una primera cita"]}'::jsonb),
('b1-049', 'es', 'descansar', 'to rest', 'Después de tanto trabajo, necesito descansar.', 'B1'::cefr_level, 'Health', ARRAY['reposar'], '{"note":"To rest/take a break; reposar is more ''lie still / let settle''. ''¡Que descanses!'' = sleep well / take care.","examples":["Descansé toda la tarde después del viaje."],"collocations":["descansar un rato","necesitar descansar"]}'::jsonb),
('b1-050', 'es', 'doler', 'to hurt, to ache', 'Me duele la cabeza desde esta mañana.', 'B1'::cefr_level, 'Health', ARRAY[]::text[], '{"grammar":"irregular o→ue; works like gustar (me duele/duelen)","note":"Used like gustar: the body part is the subject — ''me duele la cabeza'', ''me duelen los pies''. Also emotional: ''me dolió mucho''.","examples":["Después de correr le dolían las piernas."],"collocations":["me duele la cabeza","doler el estómago"]}'::jsonb),
('b1-051', 'es', 'esfuerzo', 'effort', 'Con un poco de esfuerzo, aprobarás sin problema.', 'B1'::cefr_level, 'Education', ARRAY['empeño'], '{"grammar":"m.","note":"Effort/exertion; ''hacer un esfuerzo'' = to make an effort; ''sin esfuerzo'' = effortlessly. empeño adds determination.","collocations":["hacer un esfuerzo","merecer la pena el esfuerzo"]}'::jsonb),
('b1-052', 'es', 'consejo', 'advice, piece of advice; council', 'Mi profesor me dio un buen consejo.', 'B1'::cefr_level, 'Education', ARRAY['recomendación'], '{"grammar":"m.","note":"Advice — countable in Spanish (''un consejo'' = a piece of advice); ''dar/pedir consejo''. Also ''council'' (consejo de administración).","collocations":["dar un consejo","pedir consejo"]}'::jsonb),
('b1-053', 'es', 'duda', 'doubt, question', 'Si tienes alguna duda, pregúntame.', 'B1'::cefr_level, 'Education', ARRAY['incertidumbre'], '{"grammar":"f.","note":"A doubt or a query (in class, ''una duda'' = a question). ''sin duda'' = undoubtedly; ''no cabe duda'' = there''s no question.","collocations":["tener una duda","sin duda"]}'::jsonb),
('b1-054', 'es', 'tema', 'topic, subject; issue', 'El tema de la charla fue el cambio climático.', 'B1'::cefr_level, 'Academic', ARRAY['asunto'], '{"grammar":"m. (masculine despite -a)","note":"A topic/subject of discussion; also a colloquial ''matter/issue'' and a song (''un temazo''). asunto = matter/affair.","collocations":["cambiar de tema","el tema principal"]}'::jsonb),
('b1-055', 'es', 'resumen', 'summary', 'Escribe un resumen breve del artículo.', 'B1'::cefr_level, 'Academic', ARRAY['síntesis'], '{"grammar":"m.","note":"A summary; ''en resumen'' = in short/to sum up. Verb: resumir. síntesis is a close synonym.","collocations":["en resumen","hacer un resumen"]}'::jsonb),
('b1-056', 'es', 'ejemplo', 'example', 'El profesor puso un ejemplo muy claro.', 'B1'::cefr_level, 'Academic', ARRAY['muestra'], '{"grammar":"m.","note":"An example; ''por ejemplo'' = for example; ''dar/poner un ejemplo'' = to give an example; ''predicar con el ejemplo'' = to lead by example.","collocations":["por ejemplo","poner un ejemplo"]}'::jsonb),
('b1-057', 'es', 'noticia', 'piece of news', 'Escuché la noticia en la radio esta mañana.', 'B1'::cefr_level, 'Society', ARRAY['nueva'], '{"grammar":"f.","note":"A piece of news (countable: ''una noticia''); ''las noticias'' = the news (broadcast). Not the same as periódico (newspaper).","collocations":["una buena noticia","dar una noticia"]}'::jsonb),
('b1-058', 'es', 'periódico', 'newspaper', 'Leo el periódico mientras desayuno.', 'B1'::cefr_level, 'Society', ARRAY['diario'], '{"grammar":"m.","note":"A newspaper; diario is a synonym (also = daily / a diary). As an adjective ''periódico'' = periodic/recurring.","collocations":["leer el periódico","un periódico digital"]}'::jsonb),
('b1-059', 'es', 'encuesta', 'survey, poll', 'Participé en una encuesta sobre transporte público.', 'B1'::cefr_level, 'Society', ARRAY['sondeo'], '{"grammar":"f.","note":"A survey or opinion poll; sondeo is a close synonym (esp. political polling). ''hacer una encuesta''.","collocations":["hacer una encuesta","según la encuesta"]}'::jsonb),
('b1-060', 'es', 'vecino', 'neighbour', 'Mi vecino siempre me ayuda con el jardín.', 'B1'::cefr_level, 'Society', ARRAY[]::text[], '{"grammar":"m. (vecina f.)","note":"A neighbour; also a resident of a town (''los vecinos del barrio''). As an adjective = neighbouring (el país vecino).","collocations":["el vecino de al lado","los vecinos del barrio"]}'::jsonb),
('b1-061', 'es', 'barrio', 'neighbourhood', 'Mi barrio es tranquilo y tiene muchos parques.', 'B1'::cefr_level, 'Society', ARRAY['vecindario'], '{"grammar":"m.","note":"A neighbourhood/district; ''el barrio'' can also mean the local area you''re from. vecindario = the neighbourhood/its residents.","collocations":["un barrio tranquilo","el barrio antiguo"]}'::jsonb),
('b1-062', 'es', 'medio ambiente', 'the environment', 'Debemos cuidar el medio ambiente entre todos.', 'B1'::cefr_level, 'Environment', ARRAY[]::text[], '{"grammar":"m.","note":"The natural environment (fixed phrase, usually with ''el''); adjective form: medioambiental. Not ''environment'' as in surroundings (entorno).","collocations":["cuidar el medio ambiente","el impacto en el medio ambiente"]}'::jsonb),
('b1-063', 'es', 'reciclar', 'to recycle', 'En casa intentamos reciclar todo el plástico.', 'B1'::cefr_level, 'Environment', ARRAY[]::text[], '{"note":"To recycle; also figuratively to retrain/repurpose (''reciclarse'' = to retrain professionally). Noun: reciclaje.","examples":["Recicla el vidrio y el papel por separado."],"collocations":["reciclar el plástico","reciclar residuos"]}'::jsonb),
('b1-064', 'es', 'basura', 'rubbish, trash', 'Saca la basura antes de que pase el camión.', 'B1'::cefr_level, 'Environment', ARRAY['desperdicios'], '{"grammar":"f., uncountable","note":"Rubbish/trash (uncountable); ''sacar la basura'' = take out the bin. Also figuratively junk (''comida basura'' = junk food).","collocations":["sacar la basura","comida basura"]}'::jsonb),
('b1-065', 'es', 'contaminación', 'pollution', 'La contaminación del aire es peor en la ciudad.', 'B1'::cefr_level, 'Environment', ARRAY['polución'], '{"grammar":"f.","note":"Pollution/contamination; verb: contaminar. ''contaminación acústica'' = noise pollution. polución is a close synonym.","collocations":["la contaminación del aire","reducir la contaminación"]}'::jsonb),
('b1-066', 'es', 'naturaleza', 'nature', 'Los fines de semana salimos a disfrutar de la naturaleza.', 'B1'::cefr_level, 'Environment', ARRAY[]::text[], '{"grammar":"f.","note":"Nature (the natural world), and also ''nature'' as in essential character (''la naturaleza humana''). ''en plena naturaleza'' = out in the wild.","collocations":["disfrutar de la naturaleza","la naturaleza humana"]}'::jsonb),
('b1-067', 'es', 'clima', 'climate; atmosphere', 'El clima de la costa es suave todo el año.', 'B1'::cefr_level, 'Environment', ARRAY['tiempo'], '{"grammar":"m. (masculine despite -a)","note":"Climate (long-term), and figuratively an atmosphere (''un clima de tensión''). Day-to-day weather is ''el tiempo''.","collocations":["el cambio climático","un clima cálido"]}'::jsonb),
('b1-068', 'es', 'pantalla', 'screen', 'Paso demasiadas horas delante de la pantalla.', 'B1'::cefr_level, 'Technology', ARRAY['monitor'], '{"grammar":"f.","note":"A screen (phone, TV, cinema); ''la gran pantalla'' = the big screen. monitor is specifically a computer monitor.","collocations":["la pantalla del móvil","pantalla táctil"]}'::jsonb),
('b1-069', 'es', 'contraseña', 'password', 'Olvidé la contraseña de mi correo otra vez.', 'B1'::cefr_level, 'Technology', ARRAY['clave'], '{"grammar":"f.","note":"A password; clave is a close synonym (also ''PIN/code''). ''introducir la contraseña'' = to enter the password.","collocations":["introducir la contraseña","cambiar la contraseña"]}'::jsonb),
('b1-070', 'es', 'archivo', 'file; archive', 'Guardé el archivo en una carpeta nueva.', 'B1'::cefr_level, 'Technology', ARRAY['fichero'], '{"grammar":"m.","note":"A computer file, or an archive (of records). fichero is a synonym for a file. ''adjuntar un archivo'' = to attach a file.","collocations":["guardar un archivo","adjuntar un archivo"]}'::jsonb),
('b1-071', 'es', 'red', 'network; net', 'No hay buena red en este pueblo.', 'B1'::cefr_level, 'Technology', ARRAY[]::text[], '{"grammar":"f.","note":"A network (phone signal, computer network), the internet (''la red''), or a physical net. ''las redes sociales'' = social media.","collocations":["las redes sociales","red wifi"]}'::jsonb),
('b1-072', 'es', 'aplicación', 'app; application', 'Descargué una aplicación para aprender idiomas.', 'B1'::cefr_level, 'Technology', ARRAY['app'], '{"grammar":"f.","note":"A phone/computer app (often shortened to ''app''); also ''application'' as in applying something (''la aplicación de una ley'').","collocations":["descargar una aplicación","una aplicación móvil"]}'::jsonb),
('b1-073', 'es', 'encender', 'to switch on, to light', '¿Puedes encender la luz, por favor?', 'B1'::cefr_level, 'Daily Life', ARRAY['prender'], '{"grammar":"irregular e→ie: enciendo","note":"To switch on (light, device) or light (a fire, candle). Opposite of apagar. In much of Latin America ''prender''.","examples":["Encendió la chimenea porque hacía frío."],"collocations":["encender la luz","encender el fuego"]}'::jsonb),
('b1-074', 'es', 'apagar', 'to switch off, to turn off', 'No olvides apagar el ordenador al salir.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"note":"To switch off (a device, light) or put out (a fire). Opposite of encender. Noun: apagón = blackout.","examples":["Apagué todas las luces antes de salir."],"collocations":["apagar la luz","apagar el móvil"]}'::jsonb),
('b1-075', 'es', 'enchufar', 'to plug in', 'Tengo que enchufar el móvil porque está sin batería.', 'B1'::cefr_level, 'Technology', ARRAY['conectar'], '{"note":"To plug in (into a socket, enchufe). Colloquially ''enchufe'' also = connections/pulling strings to get a job.","examples":["Enchufó el ordenador y empezó a trabajar."],"collocations":["enchufar el cargador","desenchufar"]}'::jsonb),
('b1-076', 'es', 'averiguar', 'to find out', 'Quiero averiguar a qué hora abre la tienda.', 'B1'::cefr_level, 'Daily Life', ARRAY['descubrir'], '{"grammar":"spelling: averigüé (diéresis)","note":"To find out / ascertain (by asking or investigating); descubrir = to discover. Note the ü in ''averigüé, averigüe''.","examples":["Averigüé la verdad por casualidad."],"collocations":["averiguar la verdad","averiguar qué pasó"]}'::jsonb),
('b1-077', 'es', 'elegir', 'to choose', 'Es difícil elegir entre tantas opciones.', 'B1'::cefr_level, 'Daily Life', ARRAY['seleccionar'], '{"grammar":"irregular e→i: elijo, eligió","note":"To choose or to elect (a leader). seleccionar is more ''select''. Adjective: elegido (chosen); noun: elección.","examples":["Mañana elegirán al nuevo representante."],"collocations":["elegir una opción","elegir bien"]}'::jsonb),
('b1-078', 'es', 'preocuparse', 'to worry', 'No te preocupes, todo va a salir bien.', 'B1'::cefr_level, 'Emotions', ARRAY['inquietarse'], '{"grammar":"reflexive; + por","note":"To worry (''preocuparse por'' = to worry about / to see to). Non-reflexive ''preocupar'' = to worry someone (''me preocupa'').","examples":["Se preocupa demasiado por cosas pequeñas."],"collocations":["no te preocupes","preocuparse por algo"]}'::jsonb),
('b1-079', 'es', 'alegrarse', 'to be glad, to be happy', 'Me alegro mucho de verte de nuevo.', 'B1'::cefr_level, 'Emotions', ARRAY[]::text[], '{"grammar":"reflexive; + de","note":"To be glad (''alegrarse de + inf./de que + subjunctive''). Non-reflexive ''alegrar'' = to make someone happy (''me alegra que...'').","examples":["Se alegraron mucho al recibir la noticia."],"collocations":["alegrarse de algo","me alegro por ti"]}'::jsonb),
('b1-080', 'es', 'enfadarse', 'to get angry', 'Mi hermano se enfada por cualquier cosa.', 'B1'::cefr_level, 'Emotions', ARRAY['enojarse'], '{"grammar":"reflexive; enfadarse con (alguien) / por (algo)","note":"To get angry (Spain); ''enfadarse con alguien'' = to get angry at someone. In Latin America ''enojarse'' is more common.","examples":["Se enfadó conmigo sin motivo."],"collocations":["enfadarse con alguien","enfadarse por algo"]}'::jsonb),
('b1-081', 'es', 'aburrirse', 'to get bored', 'Los niños se aburren si llueve todo el día.', 'B1'::cefr_level, 'Emotions', ARRAY[]::text[], '{"grammar":"reflexive","note":"To get bored (reflexive). Non-reflexive ''aburrir'' = to bore someone (''me aburre''). Adjective pair: aburrido (bored / boring).","examples":["Me aburrí muchísimo en la conferencia."],"collocations":["aburrirse en clase","aburrirse como una ostra"]}'::jsonb),
('b1-082', 'es', 'sorprender', 'to surprise', 'Me sorprendió su reacción tan tranquila.', 'B1'::cefr_level, 'Emotions', ARRAY['asombrar'], '{"note":"To surprise (often like gustar: ''me sorprende que...''); reflexive ''sorprenderse de'' = to be surprised. Also to catch in the act.","examples":["No me sorprende que haya ganado."],"collocations":["sorprender a alguien","no me sorprende"]}'::jsonb),
('b1-083', 'es', 'confiar', 'to trust', 'Puedes confiar en mí para lo que necesites.', 'B1'::cefr_level, 'Emotions', ARRAY['fiarse'], '{"grammar":"+ en; accent: confío, confías","note":"To trust (''confiar en alguien'') or to entrust; ''confiar en que...'' = to be confident that. fiarse (de) is the reflexive close synonym.","examples":["Confió en la persona equivocada."],"collocations":["confiar en alguien","confiar en el futuro"]}'::jsonb),
('b1-084', 'es', 'echar de menos', 'to miss (someone/something)', 'Echo de menos a mi familia cuando viajo.', 'B1'::cefr_level, 'Emotions', ARRAY['añorar'], '{"grammar":"fixed phrase","note":"Fixed expression = to miss someone/something; the person missed is the object (''te echo de menos''). In L. America also ''extrañar''.","examples":["Echábamos de menos la comida de casa."],"collocations":["echar de menos a alguien","echar de menos algo"]}'::jsonb),
('b1-085', 'es', 'orgulloso', 'proud', 'Estoy muy orgulloso de lo que has conseguido.', 'B1'::cefr_level, 'Emotions', ARRAY['satisfecho'], '{"grammar":"+ de","note":"Proud — ''orgulloso de'' = proud of (positive), but can also mean arrogant depending on tone. Noun: orgullo.","collocations":["orgulloso de","sentirse orgulloso"]}'::jsonb),
('b1-086', 'es', 'amable', 'kind, friendly', 'La recepcionista fue muy amable con nosotros.', 'B1'::cefr_level, 'Emotions', ARRAY['simpático'], '{"note":"Kind/courteous (esp. in service or manner); simpático is more ''likeable/nice''. ''muy amable'' = that''s very kind (of you).","collocations":["muy amable","amable con alguien"]}'::jsonb),
('b1-087', 'es', 'tímido', 'shy', 'De niño era muy tímido en clase.', 'B1'::cefr_level, 'Emotions', ARRAY['vergonzoso'], '{"note":"Shy/timid; noun timidez. (Careful: vergonzoso can mean shy but also ''shameful''.)","collocations":["ser tímido","una sonrisa tímida"]}'::jsonb),
('b1-088', 'es', 'valiente', 'brave', 'Fue muy valiente al hablar delante de todos.', 'B1'::cefr_level, 'Emotions', ARRAY['audaz'], '{"note":"Brave/courageous; audaz leans ''bold/daring''. Noun: valentía. Same form for m./f.","collocations":["ser valiente","una decisión valiente"]}'::jsonb),
('b1-089', 'es', 'perezoso', 'lazy', 'Los domingos me siento un poco perezoso.', 'B1'::cefr_level, 'Emotions', ARRAY['vago'], '{"note":"Lazy; vago is the more colloquial word. Noun: pereza (''me da pereza'' = I can''t be bothered). (Also ''perezoso'' = a sloth.)","collocations":["sentirse perezoso","me da pereza"]}'::jsonb),
('b1-090', 'es', 'fuerte', 'strong', 'El café de esta cafetería es muy fuerte.', 'B1'::cefr_level, 'Daily Life', ARRAY['potente'], '{"note":"Strong (physically, in flavour, intensity); also as an adverb (''hablar fuerte'' = to speak loudly). Opposite of débil.","collocations":["muy fuerte","hablar fuerte"]}'::jsonb),
('b1-091', 'es', 'débil', 'weak', 'Después de la gripe me sentía muy débil.', 'B1'::cefr_level, 'Health', ARRAY['flojo'], '{"note":"Weak (physically, or of an argument/signal); flojo is more colloquial. Opposite of fuerte. Noun: debilidad.","collocations":["sentirse débil","un punto débil"]}'::jsonb),
