('b1-094', 'es', 'lleno', 'full', 'El autobús iba completamente lleno.', 'B1'::cefr_level, 'Daily Life', ARRAY['repleto'], '{"note":"Full (''lleno de'' = full of); repleto is ''packed''. Opposite of vacío. ''estar lleno'' = to be full (also full up after eating).","collocations":["lleno de gente","estar lleno"]}'::jsonb),
('b1-095', 'es', 'vacío', 'empty', 'Encontramos el restaurante casi vacío.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"note":"Empty; also a noun ''el vacío'' = emptiness/the void. Opposite of lleno. Verb: vaciar.","collocations":["una casa vacía","sentir un vacío"]}'::jsonb),
('b1-096', 'es', 'limpio', 'clean', 'Me gusta mantener mi habitación limpia.', 'B1'::cefr_level, 'Daily Life', ARRAY['aseado'], '{"note":"Clean; also ''fair/honest'' (''juego limpio'' = fair play). Opposite of sucio. Verb: limpiar.","collocations":["mantener limpio","juego limpio"]}'::jsonb),
('b1-097', 'es', 'sucio', 'dirty', 'Los zapatos están sucios después de la lluvia.', 'B1'::cefr_level, 'Daily Life', ARRAY[]::text[], '{"note":"Dirty; also figuratively ''dirty/underhand'' (juego sucio). Opposite of limpio. Verb: ensuciar (to make dirty).","collocations":["muy sucio","ropa sucia"]}'::jsonb),
