('b1-110', 'es', 'currículum', 'CV, résumé', 'Actualicé mi currículum antes de enviarlo.', 'B1'::cefr_level, 'Business', ARRAY[]::text[], '{"grammar":"m.; also ''currículo''","note":"A CV/résumé (from ''currículum vitae'', often shortened to ''el currículum'' or colloquially ''el curri'').","collocations":["enviar el currículum","actualizar el currículum"]}'::jsonb),
('b1-111', 'es', 'contrato', 'contract', 'Firmé el contrato esta misma tarde.', 'B1'::cefr_level, 'Business', ARRAY['acuerdo'], '{"grammar":"m.","note":"A contract; verb contratar (to hire / take on). ''firmar un contrato'' = to sign a contract. acuerdo is a broader ''agreement''.","collocations":["firmar un contrato","un contrato temporal"]}'::jsonb),
('b1-112', 'es', 'deber', 'duty; to owe; must', 'Es nuestro deber respetar las normas.', 'B1'::cefr_level, 'Society', ARRAY['obligación'], '{"note":"As a noun ''el deber'' = duty (plural ''los deberes'' = homework). As a verb: ''deber + inf.'' = must/should; ''deber'' + money = to owe.","collocations":["cumplir con el deber","hacer los deberes"]}'::jsonb),
('b1-113', 'es', 'derecho', 'right; law; straight', 'Todos tenemos derecho a la educación.', 'B1'::cefr_level, 'Law', ARRAY['privilegio'], '{"note":"Three senses: a right (''derecho a''); the field of Law (estudiar Derecho); and straight/upright (''todo derecho'' = straight ahead).","collocations":["tener derecho a","los derechos humanos","todo derecho"]}'::jsonb),
('b1-114', 'es', 'norma', 'rule, norm', 'Hay que seguir las normas de seguridad.', 'B1'::cefr_level, 'Law', ARRAY['regla'], '{"grammar":"f.","note":"A rule/regulation or a social norm; regla is a close synonym (also = ruler / period). ''por norma general'' = as a rule.","collocations":["seguir las normas","una norma de seguridad"]}'::jsonb),
('b1-115', 'es', 'multa', 'fine, penalty', 'Me pusieron una multa por aparcar mal.', 'B1'::cefr_level, 'Law', ARRAY['sanción'], '{"grammar":"f.","note":"A fine/penalty; ''poner una multa'' = to give a fine; verb multar. sanción is a broader ''sanction/penalty''.","collocations":["poner una multa","una multa de tráfico"]}'::jsonb),
('b1-116', 'es', 'ciudadano', 'citizen', 'Cada ciudadano tiene el deber de votar.', 'B1'::cefr_level, 'Politics', ARRAY['habitante'], '{"grammar":"m. (ciudadana f.)","note":"A citizen; ''ciudadano de a pie'' = ordinary person. habitante = inhabitant/resident. Noun: ciudadanía.","collocations":["un ciudadano responsable","los derechos del ciudadano"]}'::jsonb),
('b1-117', 'es', 'gobierno', 'government', 'El gobierno anunció nuevas medidas hoy.', 'B1'::cefr_level, 'Politics', ARRAY[]::text[], '{"grammar":"m.","note":"The government; verb gobernar (to govern). ''el Gobierno'' (capitalised) for the specific administration.","collocations":["el gobierno central","formar gobierno"]}'::jsonb),
('b1-118', 'es', 'votar', 'to vote', 'Es importante votar en las elecciones.', 'B1'::cefr_level, 'Politics', ARRAY['elegir'], '{"note":"To vote (''votar a alguien'' / ''votar por''); noun: voto. Don''t confuse with botar (to bounce / throw out).","examples":["Votó por primera vez en las últimas elecciones."],"collocations":["votar en las elecciones","votar a favor"]}'::jsonb),
('b1-119', 'es', 'manifestación', 'demonstration, protest', 'Miles de personas asistieron a la manifestación.', 'B1'::cefr_level, 'Politics', ARRAY['protesta'], '{"grammar":"f.","note":"A public demonstration/protest (also ''a manifestation'' of something); people who attend: manifestantes. Verb: manifestarse.","collocations":["una manifestación pacífica","convocar una manifestación"]}'::jsonb),
('b1-120', 'es', 'obra', 'work (of art); construction; play', 'Esta obra de teatro es muy famosa.', 'B1'::cefr_level, 'Arts', ARRAY['creación'], '{"grammar":"f.","note":"A work (of art/literature: ''obra de arte''), a play (''obra de teatro''), or building works (''obras'' = roadworks/a building site).","collocations":["una obra de teatro","una obra de arte","estar en obras"]}'::jsonb),
('b1-121', 'es', 'cuadro', 'painting, picture; table/chart', 'Compré un cuadro para el salón.', 'B1'::cefr_level, 'Arts', ARRAY['pintura'], '{"grammar":"m.","note":"A framed painting/picture; also a table/chart (un cuadro de datos) and ''a scene''. pintura = painting (the art) or paint.","collocations":["un cuadro al óleo","colgar un cuadro"]}'::jsonb),
('b1-122', 'es', 'escenario', 'stage; scenario', 'El cantante salió al escenario entre aplausos.', 'B1'::cefr_level, 'Arts', ARRAY['tablado'], '{"grammar":"m.","note":"A theatre/concert stage, or a scenario/setting (''el peor escenario'' = the worst-case scenario). Not ''scenery'' (that''s decorado/paisaje).","collocations":["salir al escenario","el peor escenario"]}'::jsonb),
('b1-123', 'es', 'público', 'audience; public', 'El público aplaudió durante varios minutos.', 'B1'::cefr_level, 'Arts', ARRAY['audiencia'], '{"grammar":"m.","note":"The audience/spectators, or the general public; also adjective público/a (public). Opposite (adj.) of privado.","collocations":["el gran público","abierto al público"]}'::jsonb),
('b1-124', 'es', 'experimento', 'experiment', 'Hicimos un experimento sencillo en clase de ciencias.', 'B1'::cefr_level, 'Science', ARRAY['prueba'], '{"grammar":"m.","note":"A scientific experiment; verb experimentar (also = to experience/undergo). ''hacer/realizar un experimento''.","collocations":["hacer un experimento","un experimento científico"]}'::jsonb),
