('b2-118', 'es', 'carácter', 'character, personality', 'Tiene un carácter fuerte pero noble.', 'B2'::cefr_level, 'Emotions', ARRAY['temperamento'], '{"grammar":"m.; pl. caracteres (stress shifts)","note":"Character/personality (''tener carácter'' = to have a strong personality); also a typographic character. Plural: caracteres.","collocations":["un carácter fuerte","tener carácter"]}'::jsonb),
('b2-119', 'es', 'obra maestra', 'masterpiece', 'Esa novela está considerada una obra maestra.', 'B2'::cefr_level, 'Arts', ARRAY[]::text[], '{"grammar":"f.; pl. obras maestras","note":"A masterpiece (fixed phrase); the plural inflects both words: obras maestras. Built on obra (work of art).","collocations":["una obra maestra","considerada una obra maestra"]}'::jsonb),
('b2-120', 'es', 'guion', 'script, screenplay; hyphen', 'El guion de la película recibió varios premios.', 'B2'::cefr_level, 'Arts', ARRAY['libreto'], '{"grammar":"m. (also spelled guión)","note":"A film/TV script, or a hyphen/dash (-). Person: guionista (scriptwriter). libreto = libretto (opera).","collocations":["el guion de la película","escribir un guion"]}'::jsonb),
('b2-121', 'es', 'estreno', 'premiere, release', 'El estreno de la obra fue todo un acontecimiento.', 'B2'::cefr_level, 'Arts', ARRAY[]::text[], '{"grammar":"m.","note":"A premiere/opening/release (film, play), or first use of something new; verb estrenar (''estrenar zapatos'' = to wear new shoes for the first time).","collocations":["el estreno de la película","el día del estreno"]}'::jsonb),
('b2-122', 'es', 'crítica', 'review; criticism', 'La crítica elogió la actuación del protagonista.', 'B2'::cefr_level, 'Arts', ARRAY['reseña'], '{"grammar":"f.","note":"A review (of a film/book), criticism, or ''la crítica'' = the critics collectively. reseña = a written review. Adjective/verb: crítico, criticar.","collocations":["una buena crítica","hacer una crítica"]}'::jsonb),
('b2-123', 'es', 'patrimonio cultural', 'cultural heritage', 'La ciudad protege su patrimonio cultural.', 'B2'::cefr_level, 'Culture', ARRAY[]::text[], '{"grammar":"m.","note":"Cultural heritage (fixed phrase); ''Patrimonio de la Humanidad'' = World Heritage. Built on patrimonio (assets/heritage).","collocations":["el patrimonio cultural","proteger el patrimonio"]}'::jsonb),
('b2-124', 'es', 'fortalecer', 'to strengthen', 'El acuerdo busca fortalecer la cooperación entre ambos.', 'B2'::cefr_level, 'Politics', ARRAY['reforzar','robustecer'], '{"grammar":"irregular: fortalezco","note":"To strengthen (ties, an economy, muscles, resolve); from fuerte. reforzar = to reinforce. Reflexive fortalecerse = to grow stronger.","examples":["El ejercicio fortalece los músculos."],"collocations":["fortalecer los lazos","fortalecer la economía"]}'::jsonb),
('b2-125', 'es', 'garantizar', 'to guarantee, to ensure', 'El contrato pretende garantizar los derechos del cliente.', 'B2'::cefr_level, 'Law', ARRAY['asegurar','avalar'], '{"grammar":"spelling: garanticé, garantice","note":"To guarantee/ensure (rights, quality, a result); noun: garantía (guarantee/warranty). avalar = to vouch for/back.","examples":["La empresa garantizó la devolución del dinero."],"collocations":["garantizar los derechos","garantizar la calidad"]}'::jsonb),
('b2-126', 'es', 'perjudicar', 'to harm, to damage', 'El ruido constante puede perjudicar la salud.', 'B2'::cefr_level, 'Health', ARRAY['dañar','afectar'], '{"grammar":"personal a with people; spelling: perjudiqué","note":"To harm/be bad for (health, interests, reputation); dañar is more physical damage. Adjective: perjudicial (harmful). Opposite: beneficiar.","examples":["El retraso perjudicó a muchos clientes."],"collocations":["perjudicar la salud","perjudicar los intereses"]}'::jsonb),
('b2-127', 'es', 'sobrellevar', 'to cope with, to endure', 'Aprendió a sobrellevar la presión del trabajo.', 'B2'::cefr_level, 'Emotions', ARRAY['soportar','aguantar'], '{"note":"To cope with / bear (an illness, pressure, grief) — endure it while carrying on; soportar/aguantar = to put up with/stand.","examples":["Sobrellevó la enfermedad con entereza."],"collocations":["sobrellevar la presión","sobrellevar una pérdida"]}'::jsonb),
('b2-128', 'es', 'cotidiano', 'everyday, daily', 'El móvil se ha vuelto un objeto cotidiano.', 'B2'::cefr_level, 'Daily Life', ARRAY['habitual','diario'], '{"note":"Everyday/routine (''la vida cotidiana'' = everyday life); more formal than diario. habitual = usual/customary.","collocations":["la vida cotidiana","un problema cotidiano"]}'::jsonb),
('b2-129', 'es', 'previsible', 'foreseeable, predictable', 'El desenlace era totalmente previsible.', 'B2'::cefr_level, 'Society', ARRAY['esperable'], '{"note":"Foreseeable/predictable (from prever); can be neutral or mildly negative (''demasiado previsible''). Opposite: imprevisible.","collocations":["un final previsible","totalmente previsible"]}'::jsonb),
('c1-001', 'es', 'consolidar', 'to consolidate, to strengthen', 'La empresa logró consolidar su posición en el mercado.', 'C1'::cefr_level, 'Business', ARRAY['afianzar','reforzar'], '{"note":"Make something already established firmer and lasting (a position, power, friendship); afianzar/reforzar are close, but consolidar stresses durable stability.","examples":["Con los años, consolidó su prestigio como cirujano."],"collocations":["consolidar una posición","consolidar el poder","consolidar una amistad"]}'::jsonb),
('c1-002', 'es', 'vislumbrar', 'to glimpse, to make out faintly', 'Apenas se podía vislumbrar la costa entre la niebla.', 'C1'::cefr_level, 'Arts', ARRAY['entrever','atisbar'], '{"note":"Literally to barely make out through fog/distance; very common figuratively for faintly perceiving a possibility. Stronger ''barely'' sense than entrever/atisbar.","examples":["Por fin vislumbramos una salida al conflicto."],"collocations":["vislumbrar una solución","vislumbrar la costa","vislumbrar un futuro"]}'::jsonb),
('c1-003', 'es', 'esbozar', 'to sketch, to outline', 'El ponente esbozó las líneas generales del proyecto.', 'C1'::cefr_level, 'Academic', ARRAY['bosquejar','perfilar'], '{"note":"Rough out in broad strokes — a plan, an idea, or even a faint smile (esbozar una sonrisa); the most idiomatic of its synonyms for plans and ideas.","examples":["En la reunión esbozaremos las primeras ideas."],"collocations":["esbozar un plan","esbozar una sonrisa","esbozar las líneas generales"]}'::jsonb),
('c1-004', 'es', 'acentuar', 'to accentuate, to intensify', 'La crisis acentuó las diferencias entre regiones.', 'C1'::cefr_level, 'Society', ARRAY['intensificar','agravar'], '{"grammar":"also reflexive: acentuarse","note":"Make an existing quality or contrast more pronounced; like intensificar but implies sharpening something already there. Reflexive = to become more marked.","examples":["La sequía acentúa la escasez de alimentos."],"collocations":["acentuar las diferencias","acentuarse la crisis"]}'::jsonb),
('c1-005', 'es', 'atenuar', 'to mitigate, to soften', 'Las medidas buscan atenuar el impacto económico.', 'C1'::cefr_level, 'Politics', ARRAY['mitigar','suavizar'], '{"note":"Soften the force of something negative (impact, blow, pain); formal cousin of suavizar. ''Circunstancias atenuantes'' = mitigating circumstances.","examples":["Estas pastillas atenúan el dolor en pocos minutos."],"collocations":["atenuar el impacto","atenuar los efectos","circunstancias atenuantes"]}'::jsonb),
('c1-006', 'es', 'menguar', 'to diminish, to wane', 'Su entusiasmo inicial empezó a menguar con el tiempo.', 'C1'::cefr_level, 'Emotions', ARRAY['disminuir','decrecer'], '{"note":"Wane or shrink gradually (enthusiasm, light, the moon — luna menguante); more literary than disminuir.","examples":["Con el paso de los días, menguaron las provisiones."],"collocations":["menguar el entusiasmo","luna menguante"]}'::jsonb),
('c1-007', 'es', 'incrementar', 'to increase, to raise', 'El plan pretende incrementar la productividad.', 'C1'::cefr_level, 'Business', ARRAY['aumentar','elevar'], '{"grammar":"also reflexive: incrementarse","note":"Formal/business ''to increase'', often with figures or output; interchangeable with aumentar but more technical.","examples":["La empresa ha incrementado sus exportaciones un 20%."],"collocations":["incrementar la productividad","incrementar las ventas"]}'::jsonb),
('c1-008', 'es', 'ponderar', 'to weigh up, to consider carefully', 'Conviene ponderar los riesgos antes de decidir.', 'C1'::cefr_level, 'Academic', ARRAY['sopesar','valorar'], '{"note":"Weigh up pros and cons carefully before deciding; sopesar is the everyday equivalent. (Also formally ''to praise''.)","examples":["El tribunal ponderó todas las pruebas antes del fallo."],"collocations":["ponderar los riesgos","ponderar los pros y los contras"]}'::jsonb),
('c1-009', 'es', 'discrepar', 'to disagree, to differ', 'Los expertos discrepan sobre las causas del fenómeno.', 'C1'::cefr_level, 'Academic', ARRAY['disentir'], '{"grammar":"+ de / en / sobre","note":"Disagree, esp. in formal or academic debate: discrepar de alguien, en/sobre algo. More formal than ''no estar de acuerdo''.","examples":["Discrepé de su análisis en varios puntos."],"collocations":["discrepar de la opinión","discrepar en algo"]}'::jsonb),
('c1-010', 'es', 'matizar', 'to qualify, to add nuance to', 'El autor matiza sus afirmaciones en el segundo capítulo.', 'C1'::cefr_level, 'Academic', ARRAY['puntualizar','precisar'], '{"note":"Add qualifications so a statement isn''t taken absolutely — a key academic verb. precisar/puntualizar overlap, but matizar specifically softens and nuances.","examples":["Los autores matizaron sus conclusiones en la segunda edición."],"collocations":["matizar una afirmación","matizar las palabras"]}'::jsonb),
('c1-011', 'es', 'constatar', 'to verify, to confirm (a fact)', 'El estudio permitió constatar una mejora notable.', 'C1'::cefr_level, 'Science', ARRAY['comprobar','verificar'], '{"note":"Establish a fact through observation or evidence; formal, frequent in reports. comprobar is the everyday word.","examples":["Los inspectores constataron varias irregularidades."],"collocations":["constatar una mejora","constatar los hechos"]}'::jsonb),
('c1-012', 'es', 'subrayar', 'to underline, to emphasise', 'El informe subraya la urgencia de actuar.', 'C1'::cefr_level, 'Academic', ARRAY['recalcar','resaltar'], '{"note":"Literally to underline; extremely common figuratively = to stress a point. The most neutral-formal of its synonyms.","examples":["El profesor subrayó la importancia de citar las fuentes."],"collocations":["subrayar la importancia","subrayar la urgencia"]}'::jsonb),
('c1-013', 'es', 'aludir', 'to allude, to refer to', 'El ministro aludió a la situación sin dar detalles.', 'C1'::cefr_level, 'Politics', ARRAY['mencionar','referirse'], '{"grammar":"+ a","note":"Refer to something indirectly; always ''aludir a algo/alguien''. ''Darse por aludido'' = to take a remark personally.","examples":["El informe alude repetidamente a ese precedente."],"collocations":["aludir a un tema","darse por aludido"]}'::jsonb),
('c1-014', 'es', 'rehuir', 'to avoid, to shy away from', 'Rehuyó la pregunta más comprometida con elegancia.', 'C1'::cefr_level, 'Politics', ARRAY['eludir','evitar'], '{"grammar":"irregular: rehúyo, rehúye","note":"Shy away from a question, responsibility or contact, almost by instinct; slightly more evasive than eludir/evitar.","examples":["De niño rehuía el contacto con los desconocidos."],"collocations":["rehuir la pregunta","rehuir el contacto"]}'::jsonb),
('c1-015', 'es', 'eludir', 'to evade, to dodge', 'No se puede eludir la responsabilidad indefinidamente.', 'C1'::cefr_level, 'Law', ARRAY['evadir','esquivar'], '{"note":"Deliberately evade a responsibility, topic or the law; cooler and more calculated than evitar.","examples":["El sospechoso eludió la vigilancia policial."],"collocations":["eludir la responsabilidad","eludir el tema","eludir la justicia"]}'::jsonb),
('c1-016', 'es', 'rebatir', 'to refute, to counter', 'El abogado supo rebatir todos los argumentos contrarios.', 'C1'::cefr_level, 'Law', ARRAY['refutar','contradecir'], '{"note":"Counter an argument point by point; near refutar, but emphasises arguing back rather than conclusively disproving.","examples":["Rebatió cada acusación con datos concretos."],"collocations":["rebatir un argumento","rebatir las críticas"]}'::jsonb),
('c1-017', 'es', 'refutar', 'to refute, to disprove', 'Los datos refutan por completo aquella hipótesis.', 'C1'::cefr_level, 'Science', ARRAY['rebatir','desmentir'], '{"note":"Prove an argument or hypothesis false, usually with evidence; stronger and more conclusive than rebatir.","examples":["El nuevo experimento refutó la teoría anterior."],"collocations":["refutar una hipótesis","refutar una teoría"]}'::jsonb),
('c1-018', 'es', 'corroborar', 'to corroborate, to back up', 'Varios testigos corroboraron su versión de los hechos.', 'C1'::cefr_level, 'Law', ARRAY['confirmar','ratificar'], '{"note":"Back up a claim with further evidence or testimony; formal, frequent in law and science. confirmar is the everyday word.","examples":["Las imágenes corroboran su testimonio."],"collocations":["corroborar una versión","corroborar los datos"]}'::jsonb),
('c1-019', 'es', 'discernir', 'to discern, to distinguish', 'Es difícil discernir lo esencial de lo accesorio.', 'C1'::cefr_level, 'Academic', ARRAY['distinguir','diferenciar'], '{"grammar":"irregular: discierno","note":"Tell apart things that are close or subtle (essential vs trivial, right vs wrong); more cognitive than plain distinguir.","examples":["A esa edad ya disciernen entre la realidad y la ficción."],"collocations":["discernir lo esencial","discernir el bien del mal"]}'::jsonb),
('c1-020', 'es', 'deslindar', 'to delimit, to separate clearly', 'Hay que deslindar las responsabilidades de cada parte.', 'C1'::cefr_level, 'Law', ARRAY['delimitar','separar'], '{"note":"Draw clear boundaries between things, esp. responsibilities or concepts; formal/legal, often ''deslindar responsabilidades''.","examples":["El juez deslindó las competencias de cada organismo."],"collocations":["deslindar responsabilidades","deslindar competencias"]}'::jsonb),
('c1-021', 'es', 'abordar', 'to tackle, to address (an issue)', 'El congreso abordará los retos de la educación.', 'C1'::cefr_level, 'Academic', ARRAY['tratar','afrontar'], '{"note":"The go-to formal verb for taking on a problem, task or person; also literally ''to board'' a vehicle.","examples":["El documental aborda el problema desde varios ángulos."],"collocations":["abordar un problema","abordar un tema","abordar un reto"]}'::jsonb),
('c1-022', 'es', 'afianzar', 'to secure, to reinforce', 'El acuerdo sirvió para afianzar la alianza entre ambos.', 'C1'::cefr_level, 'Politics', ARRAY['consolidar','asegurar'], '{"grammar":"also reflexive: afianzarse","note":"Make something firm and secure (an alliance, position, knowledge); near consolidar but stresses giving solid support. Reflexive = to establish oneself.","examples":["Con cada victoria, el equipo afianzó su liderato."],"collocations":["afianzar una alianza","afianzarse en el cargo"]}'::jsonb),
('c1-023', 'es', 'propiciar', 'to foster, to bring about', 'El diálogo propició un clima de mayor confianza.', 'C1'::cefr_level, 'Politics', ARRAY['favorecer','facilitar'], '{"note":"Create the favourable conditions for something to happen; subtler than provocar — it enables rather than directly causes.","examples":["Un buen ambiente propicia la creatividad."],"collocations":["propiciar el diálogo","propiciar un clima de confianza"]}'::jsonb),
('c1-024', 'es', 'suscitar', 'to arouse, to provoke (interest/debate)', 'La propuesta suscitó un intenso debate público.', 'C1'::cefr_level, 'Society', ARRAY['provocar','generar'], '{"note":"Stir up an abstract reaction — interest, debate, doubt, suspicion; near provocar but more neutral and formal.","examples":["Sus declaraciones suscitan polémica cada semana."],"collocations":["suscitar interés","suscitar un debate","suscitar dudas"]}'::jsonb),
('c1-025', 'es', 'desencadenar', 'to trigger, to unleash', 'La noticia desencadenó una ola de protestas.', 'C1'::cefr_level, 'Politics', ARRAY['provocar','originar'], '{"grammar":"also reflexive: desencadenarse","note":"Trigger a chain of events (crisis, protests, reaction) — vivid image of breaking a chain. Reflexive for the events themselves.","examples":["La medida desencadena reacciones encontradas."],"collocations":["desencadenar una crisis","desencadenar una reacción"]}'::jsonb),
('c1-026', 'es', 'paliar', 'to alleviate, to ease', 'El subsidio ayudó a paliar los efectos del paro.', 'C1'::cefr_level, 'Society', ARRAY['aliviar','mitigar'], '{"note":"Ease the effects or symptoms of a problem without curing it (poverty, pain); formal cousin of aliviar. Cf. ''cuidados paliativos''.","examples":["El gobierno palió la crisis con ayudas directas."],"collocations":["paliar los efectos","paliar la situación","cuidados paliativos"]}'::jsonb),
('c1-027', 'es', 'subsanar', 'to rectify, to put right', 'La empresa se comprometió a subsanar los errores.', 'C1'::cefr_level, 'Business', ARRAY['corregir','remediar'], '{"note":"Put right an error, defect or omission, esp. administrative or legal; more formal and specific than corregir.","examples":["La empresa subsanó el fallo en cuestión de horas."],"collocations":["subsanar un error","subsanar deficiencias"]}'::jsonb),
('c1-028', 'es', 'acatar', 'to abide by, to comply with', 'Todos deben acatar las decisiones del tribunal.', 'C1'::cefr_level, 'Law', ARRAY['obedecer','cumplir'], '{"note":"Obey rules, authority or a ruling — often reluctantly but dutifully; a stronger sense of submission than cumplir.","examples":["Aunque no le gustó, acató la orden sin rechistar."],"collocations":["acatar las normas","acatar una decisión","acatar la ley"]}'::jsonb),
('c1-029', 'es', 'vulnerar', 'to violate, to infringe', 'La medida vulnera derechos fundamentales.', 'C1'::cefr_level, 'Law', ARRAY['infringir','transgredir'], '{"note":"Violate a right, law or principle; formal/legal and always abstract objects, never physical ones.","examples":["La sentencia concluyó que se vulneraron sus derechos."],"collocations":["vulnerar un derecho","vulnerar la ley","vulnerar la intimidad"]}'::jsonb),
('c1-030', 'es', 'incurrir', 'to incur, to fall into (error/offence)', 'El informe incurre en varias contradicciones.', 'C1'::cefr_level, 'Academic', ARRAY['cometer'], '{"grammar":"+ en","note":"Always ''incurrir en'' — to fall into an error, contradiction, cost or offence. Formal.","examples":["El banco incurrió en graves pérdidas ese trimestre."],"collocations":["incurrir en un error","incurrir en gastos","incurrir en un delito"]}'::jsonb),
('c1-031', 'es', 'entablar', 'to start, to strike up (a relationship/talks)', 'Las partes acordaron entablar negociaciones.', 'C1'::cefr_level, 'Politics', ARRAY['iniciar','establecer'], '{"note":"Initiate something that unfolds between parties — talks, a lawsuit, a conversation, a friendship; more specific than plain iniciar.","examples":["Pronto entablaron una sólida amistad."],"collocations":["entablar negociaciones","entablar una conversación","entablar amistad"]}'::jsonb),
('c1-032', 'es', 'deliberar', 'to deliberate', 'El jurado se retiró a deliberar durante horas.', 'C1'::cefr_level, 'Law', ARRAY['debatir','discutir'], '{"grammar":"+ sobre","note":"Debate formally before reaching a decision (juries, committees); implies weighing options, not just discussing.","examples":["El jurado deliberó durante toda la tarde."],"collocations":["deliberar sobre un caso","retirarse a deliberar"]}'::jsonb),
('c1-033', 'es', 'dictaminar', 'to rule, to give a verdict', 'El comité dictaminó a favor del demandante.', 'C1'::cefr_level, 'Law', ARRAY['sentenciar','resolver'], '{"note":"Issue an expert ruling or verdict (court, committee, doctor); formal and technical.","examples":["El perito dictaminará la causa del incendio."],"collocations":["dictaminar a favor","dictaminar sobre la causa"]}'::jsonb),
('c1-034', 'es', 'promulgar', 'to enact, to promulgate (a law)', 'El parlamento promulgó la nueva normativa.', 'C1'::cefr_level, 'Law', ARRAY['aprobar','decretar'], '{"note":"Officially put a law or decree into force; aprobar is broader (any approval), promulgar is the formal legislative act.","examples":["El rey promulgará la ley la próxima semana."],"collocations":["promulgar una ley","promulgar un decreto"]}'::jsonb),
('c1-035', 'es', 'derogar', 'to repeal, to abolish', 'El gobierno decidió derogar la antigua ley.', 'C1'::cefr_level, 'Law', ARRAY['abolir','anular'], '{"note":"Repeal an existing law — the exact opposite of promulgar; formal/legal only.","examples":["El nuevo gobierno derogó varios decretos polémicos."],"collocations":["derogar una ley","derogar una norma"]}'::jsonb),
('c1-036', 'es', 'índole', 'nature, kind, sort', 'Surgieron problemas de índole técnica.', 'C1'::cefr_level, 'Academic', ARRAY['naturaleza','tipo'], '{"grammar":"f.","note":"The ''nature/kind'' of something abstract; almost always ''de índole + adjective'' (de índole técnica/social). naturaleza is more general.","collocations":["de índole técnica","de índole social","problemas de índole..."]}'::jsonb),
('c1-037', 'es', 'envergadura', 'scale, scope, importance', 'Es un proyecto de gran envergadura.', 'C1'::cefr_level, 'Business', ARRAY['magnitud','alcance'], '{"grammar":"f.","note":"The scale or significance of an undertaking (also a bird''s wingspan); ''de gran envergadura'' = large-scale.","collocations":["de gran envergadura","un proyecto de envergadura"]}'::jsonb),
('c1-038', 'es', 'alcance', 'reach, scope', 'Aún no se conoce el alcance real del problema.', 'C1'::cefr_level, 'Academic', ARRAY['extensión'], '{"grammar":"m.","note":"Reach or scope; ''al alcance de'' = within reach of, ''de largo alcance'' = far-reaching.","collocations":["el alcance del problema","al alcance de la mano","de largo alcance"]}'::jsonb),
('c1-039', 'es', 'vertiente', 'aspect, facet; slope', 'El asunto tiene una clara vertiente ética.', 'C1'::cefr_level, 'Academic', ARRAY['faceta','aspecto'], '{"grammar":"f.","note":"One facet or side of an issue (also a mountainside); use to flag a single dimension of a topic. faceta is synonymous.","collocations":["la vertiente ética","la vertiente económica"]}'::jsonb),
('c1-040', 'es', 'matiz', 'nuance, shade of meaning', 'Cada palabra aporta un matiz distinto.', 'C1'::cefr_level, 'Arts', ARRAY['tono','sutileza'], '{"grammar":"m., pl. matices","note":"A subtle shade of meaning or colour; ''sin matices'' = black-and-white/categorical.","collocations":["un matiz distinto","sin matices","matices de significado"]}'::jsonb),
('c1-041', 'es', 'sesgo', 'bias; slant', 'El estudio presenta un evidente sesgo ideológico.', 'C1'::cefr_level, 'Academic', ARRAY['parcialidad','inclinación'], '{"grammar":"m.","note":"Bias or slant in data/reporting; technical in statistics (''sesgo de selección''). ''Al sesgo'' = on the bias/diagonally.","collocations":["sesgo ideológico","sesgo de selección"]}'::jsonb),
('c1-042', 'es', 'premisa', 'premise', 'Su razonamiento parte de una premisa falsa.', 'C1'::cefr_level, 'Academic', ARRAY['supuesto'], '{"grammar":"f.","note":"A premise an argument rests on; ''partir de la premisa de que...''. supuesto is close.","collocations":["partir de una premisa","una premisa falsa"]}'::jsonb),
('c1-043', 'es', 'hipótesis', 'hypothesis', 'Los datos contradicen la hipótesis inicial.', 'C1'::cefr_level, 'Science', ARRAY['conjetura','suposición'], '{"grammar":"f., invariable (la/las hipótesis)","note":"Hypothesis; same form singular and plural. ''Plantear/contrastar una hipótesis''.","collocations":["plantear una hipótesis","contrastar la hipótesis"]}'::jsonb),
