('c1-107', 'es', 'secuela', 'after-effect, sequel', 'El accidente le dejó secuelas permanentes.', 'C1'::cefr_level, 'Health', ARRAY['consecuencia'], '{"grammar":"f.","note":"A lasting after-effect of illness or trauma (usually plural: secuelas); also a film sequel. consecuencia is more general.","collocations":["dejar secuelas","secuelas permanentes"]}'::jsonb),
('c1-108', 'es', 'propenso', 'prone, liable', 'Es propenso a sufrir resfriados en invierno.', 'C1'::cefr_level, 'Health', ARRAY['proclive','predispuesto'], '{"grammar":"+ a","note":"Prone or liable to (illness, mistakes): ''propenso a + noun/infinitive''. proclive is close, often for behaviours.","collocations":["propenso a resfriados","propenso a sufrir"]}'::jsonb),
('c1-109', 'es', 'sedentario', 'sedentary', 'Un estilo de vida sedentario perjudica la salud.', 'C1'::cefr_level, 'Health', ARRAY[]::text[], '{"note":"Sedentary — of lifestyle or work, and of peoples (vs nomadic); opposite of activo/nómada. ''Vida sedentaria''.","collocations":["vida sedentaria","estilo de vida sedentario"]}'::jsonb),
('c1-110', 'es', 'biodiversidad', 'biodiversity', 'La selva alberga una enorme biodiversidad.', 'C1'::cefr_level, 'Environment', ARRAY[]::text[], '{"grammar":"f.","note":"The variety of life in an ecosystem; environmental term. ''Pérdida de biodiversidad''.","collocations":["pérdida de biodiversidad","rica biodiversidad"]}'::jsonb),
('c1-111', 'es', 'ecosistema', 'ecosystem', 'La contaminación amenaza todo el ecosistema marino.', 'C1'::cefr_level, 'Environment', ARRAY[]::text[], '{"grammar":"m. (despite -a ending)","note":"Ecosystem, literal and figurative (ecosistema digital). Despite the -a ending it is masculine.","collocations":["ecosistema marino","el equilibrio del ecosistema"]}'::jsonb),
('c1-112', 'es', 'deforestación', 'deforestation', 'La deforestación avanza a un ritmo alarmante.', 'C1'::cefr_level, 'Environment', ARRAY[]::text[], '{"grammar":"f.","note":"Deforestation; ''avanzar/frenar la deforestación''. Opposite of reforestación.","collocations":["frenar la deforestación","la deforestación de la selva"]}'::jsonb),
('c1-113', 'es', 'vertido', 'spill, discharge', 'El vertido de petróleo afectó a toda la costa.', 'C1'::cefr_level, 'Environment', ARRAY['derrame'], '{"grammar":"m.","note":"A spill or discharge of waste into the environment; from verter. derrame is close, often used for oil.","collocations":["vertido de petróleo","vertidos tóxicos"]}'::jsonb),
('c1-114', 'es', 'huella', 'footprint, mark, trace', 'Cada uno puede reducir su huella de carbono.', 'C1'::cefr_level, 'Environment', ARRAY['rastro','marca'], '{"grammar":"f.","note":"Footprint or trace, literal and figurative; ''huella de carbono'' = carbon footprint, ''dejar huella'' = to leave a mark, ''huellas dactilares'' = fingerprints.","collocations":["huella de carbono","dejar huella","huellas dactilares"]}'::jsonb),
('c1-115', 'es', 'yacimiento', 'deposit, site (mineral/archaeological)', 'Descubrieron un importante yacimiento arqueológico.', 'C1'::cefr_level, 'Science', ARRAY['mina'], '{"grammar":"m.","note":"A deposit or site — mineral, oil or archaeological; context decides which. ''Yacimiento petrolífero/arqueológico''.","collocations":["yacimiento arqueológico","yacimiento petrolífero"]}'::jsonb),
('c1-116', 'es', 'legado', 'legacy', 'Su legado artístico sigue influyendo hoy.', 'C1'::cefr_level, 'Culture', ARRAY['herencia'], '{"grammar":"m.","note":"Legacy — what someone leaves behind (cultural, artistic, or an inheritance). herencia overlaps but is more material/legal.","collocations":["legado cultural","dejar un legado"]}'::jsonb),
('c1-117', 'es', 'acervo', 'heritage, body (of knowledge/works)', 'El museo conserva un valioso acervo cultural.', 'C1'::cefr_level, 'Culture', ARRAY['patrimonio','conjunto'], '{"grammar":"m.","note":"A shared body of heritage, knowledge or works; formal, very often ''acervo cultural''. patrimonio is close.","collocations":["acervo cultural","el acervo común"]}'::jsonb),
('c1-118', 'es', 'mecenas', 'patron, sponsor', 'El artista contó con el apoyo de un generoso mecenas.', 'C1'::cefr_level, 'Arts', ARRAY['patrocinador','benefactor'], '{"grammar":"m./f., invariable","note":"A patron who funds the arts (from Maecenas); same form sg/pl. patrocinador is the modern, commercial term.","collocations":["un generoso mecenas","el mecenas de las artes"]}'::jsonb),
('c1-119', 'es', 'narrativa', 'narrative', 'La novela destaca por su cuidada narrativa.', 'C1'::cefr_level, 'Arts', ARRAY['relato'], '{"grammar":"f.","note":"Narrative — both the craft of storytelling and, in modern usage, a political ''narrative'' or spin. relato is a single story.","collocations":["una cuidada narrativa","la narrativa política"]}'::jsonb),
('c1-120', 'es', 'estética', 'aesthetics; aesthetic (adj.)', 'La película apuesta por una estética minimalista.', 'C1'::cefr_level, 'Arts', ARRAY[]::text[], '{"grammar":"f.","note":"Aesthetics or a visual style (''una estética minimalista''); also the adjective estético/a, and the beauty-salon sense (centro de estética).","collocations":["una estética minimalista","la estética del film"]}'::jsonb),
('c1-121', 'es', 'acotar', 'to delimit, to narrow down', 'Conviene acotar bien el alcance del estudio.', 'C1'::cefr_level, 'Academic', ARRAY['delimitar','restringir'], '{"note":"Narrow down or delimit scope (a study, topic, quote); also to annotate. delimitar is close, acotar adds a ''fence in'' sense.","examples":["El comité acotó el alcance de la investigación."],"collocations":["acotar el alcance","acotar el tema"]}'::jsonb),
('c1-122', 'es', 'cotejar', 'to compare, to collate', 'Cotejaron las dos versiones para hallar diferencias.', 'C1'::cefr_level, 'Academic', ARRAY['comparar','contrastar'], '{"note":"Cross-check two versions or documents side by side; formal. comparar is general, cotejar implies careful collation.","examples":["El editor coteja cada cita con el original."],"collocations":["cotejar dos versiones","cotejar datos"]}'::jsonb),
('c1-123', 'es', 'dilatar', 'to prolong, to delay; to dilate', 'No conviene dilatar más la decisión.', 'C1'::cefr_level, 'Business', ARRAY['retrasar','prolongar'], '{"grammar":"also reflexive: dilatarse","note":"Drag out or postpone (a decision) — reflexive dilatarse = to drag on; also physically to dilate (pupils). retrasar is plainer.","examples":["El trámite se dilató varios meses sin explicación."],"collocations":["dilatar una decisión","dilatarse en el tiempo"]}'::jsonb),
('c1-124', 'es', 'tajante', 'categorical, emphatic, blunt', 'Dio una negativa tajante, sin lugar a réplica.', 'C1'::cefr_level, 'Society', ARRAY['rotundo','categórico'], '{"note":"Blunt and categorical, allowing no reply (a ''no'', a tone); near rotundo, but tajante adds a cutting edge.","collocations":["una negativa tajante","un tono tajante"]}'::jsonb),
('c2-001', 'es', 'diáfano', 'crystal-clear, transparent, limpid', 'Ofreció una explicación diáfana, sin la menor ambigüedad.', 'C2'::cefr_level, 'Academic', ARRAY['nítido','claro'], '{"note":"Crystal-clear — of light/air/water, and figuratively of prose or explanations; more literary than claro, with a sense of luminous transparency.","collocations":["una explicación diáfana","un cielo diáfano","un espacio diáfano"]}'::jsonb),
('c2-002', 'es', 'prístino', 'pristine, untouched, original', 'El valle conserva su belleza prístina.', 'C2'::cefr_level, 'Environment', ARRAY['puro','intacto'], '{"note":"Pristine and untouched, esp. of nature or an original state; literary. ''belleza/estado prístino''. puro is the plain word.","collocations":["belleza prístina","en estado prístino"]}'::jsonb),
('c2-003', 'es', 'inefable', 'ineffable, indescribable', 'Sintió una alegría inefable al volver a casa.', 'C2'::cefr_level, 'Emotions', ARRAY['indescriptible','inenarrable'], '{"note":"So overwhelming it can''t be put into words (joy, beauty); elevated/literary. indescriptible is the everyday equivalent.","collocations":["una alegría inefable","una belleza inefable"]}'::jsonb),
('c2-004', 'es', 'efímero', 'ephemeral, fleeting', 'La fama suele ser tan efímera como intensa.', 'C2'::cefr_level, 'Culture', ARRAY['fugaz','pasajero'], '{"note":"Lasting only a moment (fame, beauty, pleasure); fugaz is close, efímero stresses brief existence. Opposite of perenne.","collocations":["la fama efímera","un placer efímero"]}'::jsonb),
('c2-005', 'es', 'perenne', 'perennial, everlasting', 'Su obra goza de una vigencia perenne.', 'C2'::cefr_level, 'Culture', ARRAY['perpetuo','imperecedero'], '{"note":"Everlasting; also botanically perennial (de hoja perenne). perpetuo/imperecedero are close. Opposite of efímero.","collocations":["de hoja perenne","una vigencia perenne"]}'::jsonb),
('c2-006', 'es', 'sucinto', 'succinct, concise', 'Redactó un informe sucinto pero completo.', 'C2'::cefr_level, 'Academic', ARRAY['conciso','breve'], '{"note":"Briefly complete — saying all that''s needed in few words; conciso is close, sucinto adds economy. Opposite of prolijo.","collocations":["un informe sucinto","de forma sucinta"]}'::jsonb),
('c2-007', 'es', 'prolijo', 'long-winded; overly detailed', 'El discurso resultó prolijo y algo tedioso.', 'C2'::cefr_level, 'Academic', ARRAY['extenso','farragoso'], '{"note":"Tiresomely long-winded or over-detailed; negative, the opposite of sucinto. (In parts of Latin America also = meticulously neat.)","collocations":["un discurso prolijo","una explicación prolija"]}'::jsonb),
('c2-008', 'es', 'escueto', 'terse, brief, plain', 'Su respuesta fue escueta y tajante.', 'C2'::cefr_level, 'Society', ARRAY['conciso','parco'], '{"note":"Terse and bare-bones, stripped of anything extra; parco is close. Of statements, answers, style.","collocations":["una respuesta escueta","un estilo escueto"]}'::jsonb),
('c2-009', 'es', 'contundente', 'forceful, conclusive, emphatic', 'Aportó pruebas contundentes ante el tribunal.', 'C2'::cefr_level, 'Law', ARRAY['rotundo','concluyente'], '{"note":"Forceful and leaving no doubt — proof, an argument, a victory, a blow; rotundo is close, contundente adds weight and impact.","collocations":["pruebas contundentes","una victoria contundente"]}'::jsonb),
('c2-010', 'es', 'fehaciente', 'irrefutable, reliable (proof)', 'Presentó un documento fehaciente de la transacción.', 'C2'::cefr_level, 'Law', ARRAY['irrefutable','fidedigno'], '{"note":"Providing irrefutable proof; formal/legal. ''de forma fehaciente'' = verifiably. fidedigno is close.","collocations":["prueba fehaciente","de forma fehaciente"]}'::jsonb),
('c2-011', 'es', 'consabido', 'well-known, usual, aforementioned', 'Terminó con el consabido agradecimiento al público.', 'C2'::cefr_level, 'Society', ARRAY['acostumbrado','habitual'], '{"note":"The well-known, expected one already understood by all — often with mild irony about its predictability. habitual is neutral.","collocations":["el consabido agradecimiento","la consabida excusa"]}'::jsonb),
('c2-012', 'es', 'inveterado', 'inveterate, deep-rooted, long-standing', 'Tenía la inveterada costumbre de madrugar.', 'C2'::cefr_level, 'Culture', ARRAY['arraigado','crónico'], '{"note":"Long-standing and deeply ingrained, esp. habits; arraigado is close, inveterado stresses age. Often faintly negative.","collocations":["una costumbre inveterada","un hábito inveterado"]}'::jsonb),
('c2-013', 'es', 'perentorio', 'urgent, peremptory, pressing', 'El plazo perentorio no admitía demoras.', 'C2'::cefr_level, 'Law', ARRAY['urgente','apremiante'], '{"grammar":"formal/legal","note":"Pressingly urgent, brooking no delay; in law, a final deadline. apremiante is close, perentorio more categorical.","collocations":["un plazo perentorio","de forma perentoria"]}'::jsonb),
('c2-014', 'es', 'exiguo', 'meagre, scanty', 'Disponían de un presupuesto exiguo para la obra.', 'C2'::cefr_level, 'Finance', ARRAY['escaso','insuficiente'], '{"note":"Too small to suffice — budget, salary, number; escaso is close, exiguo more formal/literary.","collocations":["un presupuesto exiguo","una cantidad exigua"]}'::jsonb),
('c2-015', 'es', 'ingente', 'huge, enormous', 'Reunir el archivo exigió un esfuerzo ingente.', 'C2'::cefr_level, 'Academic', ARRAY['enorme','colosal'], '{"note":"Vast in scale or effort; literary. enorme is plainer. Often ''un esfuerzo/una cantidad ingente''.","collocations":["un esfuerzo ingente","una cantidad ingente"]}'::jsonb),
('c2-016', 'es', 'ínfimo', 'minimal, lowest, negligible', 'La diferencia entre ambos resultados es ínfima.', 'C2'::cefr_level, 'Science', ARRAY['mínimo','insignificante'], '{"note":"The very lowest or tiniest; superlative in feel. mínimo is close, ínfimo more emphatic. Opposite of máximo.","collocations":["una cantidad ínfima","un precio ínfimo"]}'::jsonb),
('c2-017', 'es', 'magno', 'great, grand', 'Organizaron un magno acto conmemorativo.', 'C2'::cefr_level, 'Culture', ARRAY['grandioso','ilustre'], '{"grammar":"usually before the noun","note":"Grand or great, in solemn set phrases (magno acto, magna obra, Alejandro Magno); fixed, elevated register.","collocations":["un magno acto","una obra magna"]}'::jsonb),
('c2-018', 'es', 'soslayo', 'sideways glance (de soslayo: sidelong)', 'Lo miró de soslayo, sin atreverse a hablar.', 'C2'::cefr_level, 'Emotions', ARRAY['reojo'], '{"grammar":"m., chiefly in ''de soslayo''","note":"Almost always ''de soslayo'' = sidelong / out of the corner of one''s eye, or evasively. Same idea as ''de reojo''.","collocations":["mirar de soslayo","de soslayo"]}'::jsonb),
('c2-019', 'es', 'atisbo', 'hint, glimmer, trace', 'No había en su rostro el menor atisbo de duda.', 'C2'::cefr_level, 'Emotions', ARRAY['indicio','vestigio'], '{"grammar":"m.","note":"A faint first trace of something (doubt, hope, a smile); ''ni el menor atisbo de'' = not the slightest hint of. indicio is close.","collocations":["un atisbo de duda","el menor atisbo de"]}'::jsonb),
('c2-020', 'es', 'vestigio', 'vestige, remnant, trace', 'Solo quedan vestigios de la antigua muralla.', 'C2'::cefr_level, 'Culture', ARRAY['resto','huella'], '{"grammar":"m.","note":"A surviving trace of something now gone (ruins, customs); often plural. resto is plainer, vestigio more evocative.","collocations":["vestigios del pasado","los últimos vestigios"]}'::jsonb),
('c2-021', 'es', 'quimera', 'pipe dream, chimera', 'La paz perpetua le parecía una quimera.', 'C2'::cefr_level, 'Politics', ARRAY['ilusión','utopía'], '{"grammar":"f.","note":"An impossible dream chased in vain; literary. utopía is close but more political/ideal. ''perseguir quimeras''.","collocations":["una quimera imposible","perseguir quimeras"]}'::jsonb),
('c2-022', 'es', 'utopía', 'utopia', 'Aquella sociedad ideal era una pura utopía.', 'C2'::cefr_level, 'Politics', ARRAY['ideal','quimera'], '{"grammar":"f.","note":"An ideal but unattainable society or goal; quimera is close, utopía carries the political/philosophical sense. Adjective: utópico.","collocations":["una utopía irrealizable","una sociedad utópica"]}'::jsonb),
('c2-023', 'es', 'albedrío', 'free will, discretion', 'Actuó por su libre albedrío, sin presiones.', 'C2'::cefr_level, 'Society', ARRAY['voluntad','arbitrio'], '{"grammar":"m.","note":"Free will / one''s own discretion; almost always ''libre albedrío'' or ''a su albedrío'' (as one pleases). voluntad is plainer.","collocations":["libre albedrío","a su albedrío"]}'::jsonb),
('c2-024', 'es', 'idiosincrasia', 'idiosyncrasy, distinctive character', 'El humor forma parte de la idiosincrasia del país.', 'C2'::cefr_level, 'Culture', ARRAY['carácter','identidad'], '{"grammar":"f.","note":"The distinctive character of a people or person; formal. carácter/identidad are close. Adjective: idiosincrásico.","collocations":["la idiosincrasia del país","formar parte de la idiosincrasia"]}'::jsonb),
('c2-025', 'es', 'menester', 'need, necessity; task', 'Es menester revisar el contrato antes de firmarlo.', 'C2'::cefr_level, 'Law', ARRAY['necesidad','precisión'], '{"grammar":"m.","note":"Two uses: ''es menester + inf.'' = it is necessary to (formal ''hay que''); and plural ''menesteres'' = tasks/duties. necesidad is plainer.","collocations":["es menester","los menesteres diarios"]}'::jsonb),
('c2-026', 'es', 'óbice', 'obstacle, impediment', 'La distancia no fue óbice para mantener la amistad.', 'C2'::cefr_level, 'Society', ARRAY['impedimento','obstáculo'], '{"grammar":"m., chiefly negated","note":"An obstacle — almost always ''no ser óbice para'' = to be no bar to. impedimento is the plain word.","collocations":["no ser óbice para","sin óbice"]}'::jsonb),
('c2-027', 'es', 'menoscabo', 'detriment, impairment', 'Defendió sus ideas sin menoscabo de las ajenas.', 'C2'::cefr_level, 'Law', ARRAY['perjuicio','daño'], '{"grammar":"m.","note":"Damage to something valued; ''en/sin menoscabo de'' = to/without the detriment of. The noun of menoscabar; perjuicio is plainer.","collocations":["sin menoscabo de","en menoscabo de"]}'::jsonb),
('c2-028', 'es', 'salvedad', 'proviso, reservation, exception', 'Aceptó el plan con una única salvedad.', 'C2'::cefr_level, 'Law', ARRAY['excepción','reserva'], '{"grammar":"f.","note":"A caveat attached to an agreement; ''con la salvedad de que...'' = with the proviso that. excepción is close.","collocations":["con la salvedad de que","hacer una salvedad"]}'::jsonb),
('c2-029', 'es', 'cariz', 'look, aspect (that a situation takes on)', 'El conflicto tomó un cariz preocupante.', 'C2'::cefr_level, 'Politics', ARRAY['aspecto','sesgo'], '{"grammar":"m.","note":"The look or turn a situation is taking; ''tomar mal/buen cariz''. aspecto is plainer, cariz implies a developing trend.","collocations":["tomar mal cariz","el cariz del asunto"]}'::jsonb),
('c2-030', 'es', 'tesitura', 'situation, frame of mind, predicament', 'En aquella difícil tesitura, optó por callar.', 'C2'::cefr_level, 'Society', ARRAY['situación','coyuntura'], '{"grammar":"f.","note":"A tricky situation one is placed in (also a voice''s range in music); ''en esta tesitura''. coyuntura is close.","collocations":["en esta tesitura","una difícil tesitura"]}'::jsonb),
('c2-031', 'es', 'albur', 'chance, risk, hazard', 'Dejó su futuro al albur de una sola decisión.', 'C2'::cefr_level, 'Society', ARRAY['azar','riesgo'], '{"grammar":"m.","note":"Pure chance/risk; ''al albur de'' = at the mercy of. azar is plainer, albur stresses the gamble. (In Mexico also a pun.)","collocations":["al albur de","correr el albur"]}'::jsonb),
('c2-032', 'es', 'ardid', 'ruse, scheme, trick', 'Descubrieron el ardid antes de que surtiera efecto.', 'C2'::cefr_level, 'Law', ARRAY['artimaña','treta'], '{"grammar":"m.","note":"A clever ruse to deceive or gain advantage; artimaña/treta are close. Neutral-to-negative.","collocations":["un ardid para","recurrir a un ardid"]}'::jsonb),
('c2-033', 'es', 'subterfugio', 'subterfuge, evasion', 'Recurrió a un subterfugio para eludir la pregunta.', 'C2'::cefr_level, 'Politics', ARRAY['evasiva','pretexto'], '{"grammar":"m.","note":"An evasive dodge to avoid something; evasiva/pretexto are close, subterfugio more formal. ''recurrir a subterfugios''.","collocations":["recurrir a un subterfugio","sin subterfugios"]}'::jsonb),
('c2-034', 'es', 'argucia', 'sophistry, cunning trick', 'Sus argucias legales retrasaron el juicio.', 'C2'::cefr_level, 'Law', ARRAY['sofisma','astucia'], '{"grammar":"f.","note":"A specious, cunning argument — esp. legal hair-splitting; sofisma is close. Pejorative.","collocations":["argucias legales","una mera argucia"]}'::jsonb),
('c2-035', 'es', 'connivencia', 'collusion, connivance', 'Actuaron en connivencia con las autoridades locales.', 'C2'::cefr_level, 'Politics', ARRAY['complicidad','confabulación'], '{"grammar":"f.","note":"Secret collusion in wrongdoing; ''en connivencia con'' = in cahoots with. complicidad is close.","collocations":["en connivencia con","actuar en connivencia"]}'::jsonb),
('c2-036', 'es', 'fehaciencia', 'reliability, authenticity (of proof)', 'La fehaciencia del documento quedó acreditada.', 'C2'::cefr_level, 'Law', ARRAY['autenticidad'], '{"grammar":"f.","note":"The quality of being irrefutable proof; rare, formal/legal noun of fehaciente. autenticidad is close.","collocations":["la fehaciencia del documento","acreditar la fehaciencia"]}'::jsonb),
('c2-037', 'es', 'ecuánime', 'even-handed, impartial, level-headed', 'El árbitro se mostró ecuánime en todo momento.', 'C2'::cefr_level, 'Law', ARRAY['imparcial','sereno'], '{"note":"Even-handed and composed under pressure; imparcial stresses fairness, ecuánime adds calm balance. Noun: ecuanimidad.","collocations":["un juez ecuánime","un juicio ecuánime"]}'::jsonb),
('c2-038', 'es', 'displicente', 'offhand, disdainful', 'Respondió con un tono displicente y altivo.', 'C2'::cefr_level, 'Emotions', ARRAY['desdeñoso','indiferente'], '{"note":"Coolly offhand, showing bored disdain; desdeñoso is close. Of tone, gesture, manner.","collocations":["un tono displicente","un gesto displicente"]}'::jsonb),
('c2-039', 'es', 'altanero', 'haughty, arrogant', 'Su gesto altanero molestó a los presentes.', 'C2'::cefr_level, 'Emotions', ARRAY['soberbio','altivo'], '{"note":"Haughtily superior; altivo/soberbio are close. Of look, gesture, bearing.","collocations":["un gesto altanero","una actitud altanera"]}'::jsonb),
('c2-040', 'es', 'pusilánime', 'faint-hearted, cowardly', 'No fue pusilánime: defendió su postura con firmeza.', 'C2'::cefr_level, 'Emotions', ARRAY['cobarde','timorato'], '{"note":"Lacking the courage to act or decide; cobarde is the blunt word, pusilánime is formal and weaker-willed.","collocations":["un gesto pusilánime","mostrarse pusilánime"]}'::jsonb),
('c2-041', 'es', 'magnánimo', 'magnanimous, generous in spirit', 'Se mostró magnánimo con sus adversarios.', 'C2'::cefr_level, 'Emotions', ARRAY['generoso','noble'], '{"note":"Nobly generous, esp. to rivals or the defeated; generoso is plainer, magnánimo adds greatness of spirit. Noun: magnanimidad.","collocations":["magnánimo con los vencidos","un gesto magnánimo"]}'::jsonb),
('c2-042', 'es', 'sagaz', 'shrewd, astute', 'Una observadora sagaz no pasaría por alto ese detalle.', 'C2'::cefr_level, 'Emotions', ARRAY['perspicaz','astuto'], '{"note":"Shrewd at reading people and situations; perspicaz/astuto are close, sagaz adds cunning foresight.","collocations":["una mente sagaz","un político sagaz"]}'::jsonb),
('c2-043', 'es', 'taciturno', 'taciturn, sullen, withdrawn', 'Desde la noticia, se volvió huraño y taciturno.', 'C2'::cefr_level, 'Emotions', ARRAY['callado','reservado'], '{"note":"Habitually silent and withdrawn, often gloomy; callado describes the moment, taciturno the temperament.","collocations":["un hombre taciturno","huraño y taciturno"]}'::jsonb),
('c2-044', 'es', 'locuaz', 'talkative, loquacious', 'El invitado, muy locuaz, animó la tertulia.', 'C2'::cefr_level, 'Emotions', ARRAY['parlanchín','elocuente'], '{"note":"Very talkative, with ready fluency; parlanchín is colloquial, locuaz more neutral. Opposite of taciturno.","collocations":["un invitado locuaz","mostrarse locuaz"]}'::jsonb),
('c2-045', 'es', 'veleidoso', 'fickle, capricious', 'Su carácter veleidoso le impedía mantener un plan.', 'C2'::cefr_level, 'Emotions', ARRAY['voluble','inconstante'], '{"note":"Fickle, forever changing whims and loyalties; voluble/inconstante are close. Of character, affections.","collocations":["un carácter veleidoso","un amante veleidoso"]}'::jsonb),
('c2-046', 'es', 'denodado', 'valiant, dauntless, strenuous', 'Hizo un esfuerzo denodado por terminar a tiempo.', 'C2'::cefr_level, 'Society', ARRAY['valeroso','esforzado'], '{"note":"Valiantly strenuous — of effort, defence, struggle; literary. esforzado is close, denodado adds fearlessness.","collocations":["un esfuerzo denodado","una denodada defensa"]}'::jsonb),
('c2-047', 'es', 'abnegado', 'self-sacrificing, selfless', 'Recordaron la abnegada labor del personal sanitario.', 'C2'::cefr_level, 'Health', ARRAY['altruista','entregado'], '{"note":"Selflessly devoted, putting others first; altruista is close, abnegado stresses sacrifice. Often of carers, parents.","collocations":["una labor abnegada","una madre abnegada"]}'::jsonb),
