('c2-108', 'es', 'pujante', 'thriving, vigorous, surging', 'Lidera un sector pujante y lleno de talento.', 'C2'::cefr_level, 'Business', ARRAY['floreciente','vigoroso'], '{"note":"Vigorously growing — a sector, economy, movement; floreciente/vigoroso are close, pujante adds surging momentum.","collocations":["un sector pujante","una economía pujante"]}'::jsonb),
('c2-109', 'es', 'lucrativo', 'lucrative, profitable', 'Convirtió su afición en un negocio lucrativo.', 'C2'::cefr_level, 'Finance', ARRAY['rentable','provechoso'], '{"note":"Bringing good profit; rentable is close, lucrativo can hint at money-driven. Cf. ''sin ánimo de lucro'' (non-profit).","collocations":["un negocio lucrativo","sin fines lucrativos"]}'::jsonb),
('c2-110', 'es', 'sufragar', 'to defray, to cover the cost of', 'Una beca sufragó por completo sus estudios.', 'C2'::cefr_level, 'Finance', ARRAY['costear','financiar'], '{"note":"To pay for / cover the cost of (studies, expenses); costear/financiar are close. (Also ''sufragar'' = to vote, in some contexts.)","examples":["El ayuntamiento sufragará las obras del nuevo parque."],"collocations":["sufragar los gastos","sufragar los estudios"]}'::jsonb),
('c2-111', 'es', 'munificencia', 'munificence, lavish generosity', 'El museo nació de la munificencia de un coleccionista.', 'C2'::cefr_level, 'Culture', ARRAY['generosidad','largueza'], '{"grammar":"f.","note":"Lavish, lordly generosity, esp. of a patron; generosidad is plainer, munificencia formal/literary. Cf. mecenas.","collocations":["la munificencia de","con munificencia"]}'::jsonb),
('c2-112', 'es', 'austeridad', 'austerity, severity', 'Vivía con una austeridad casi monacal.', 'C2'::cefr_level, 'Finance', ARRAY['sobriedad','frugalidad'], '{"grammar":"f.","note":"Severe plainness or thrift, by choice or policy; sobriedad/frugalidad are close. ''medidas de austeridad''.","collocations":["medidas de austeridad","vivir con austeridad"]}'::jsonb),
('c2-113', 'es', 'prodigar', 'to lavish, to give generously', 'Le prodigaron toda clase de atenciones.', 'C2'::cefr_level, 'Society', ARRAY['derrochar','colmar'], '{"grammar":"often reflexive: prodigarse","note":"To lavish (attention, praise) freely; reflexive ''prodigarse en'' = to be generous with / appear often. derrochar/colmar are close.","examples":["Rara vez prodiga elogios sin un buen motivo."],"collocations":["prodigar atenciones","prodigar elogios"]}'::jsonb),
('c2-114', 'es', 'esmero', 'great care, painstaking effort', 'Restauró el cuadro con sumo esmero.', 'C2'::cefr_level, 'Arts', ARRAY['cuidado','dedicación'], '{"grammar":"m.","note":"Painstaking care put into doing something well; cuidado/dedicación are close. ''con (sumo) esmero''.","collocations":["con esmero","con sumo esmero"]}'::jsonb),
('c2-115', 'es', 'pericia', 'expertise, skill', 'Maniobró con la pericia de un veterano.', 'C2'::cefr_level, 'Business', ARRAY['destreza','maestría'], '{"grammar":"f.","note":"Practised skill or expertise at a craft; destreza/maestría are close. ''con pericia''. Adjective: perito (expert).","collocations":["con pericia","una gran pericia"]}'::jsonb),
('c2-116', 'es', 'maestría', 'mastery, great skill', 'Tocó la pieza con absoluta maestría.', 'C2'::cefr_level, 'Arts', ARRAY['pericia','virtuosismo'], '{"grammar":"f.","note":"Consummate mastery of an art or skill; pericia is close, maestría implies the highest command. (In Latin America also a master''s degree.)","collocations":["con maestría","absoluta maestría"]}'::jsonb),
('c2-117', 'es', 'acuciante', 'pressing, urgent', 'La escasez de agua es un problema acuciante.', 'C2'::cefr_level, 'Environment', ARRAY['apremiante','urgente'], '{"note":"Pressing and demanding immediate attention — a need, problem; apremiante/urgente are close. From acuciar.","collocations":["un problema acuciante","una necesidad acuciante"]}'::jsonb),
('c2-118', 'es', 'soslayo cultural', 'cultural sidelining/neglect', 'Denunció el soslayo cultural de las lenguas minoritarias.', 'C2'::cefr_level, 'Culture', ARRAY[]::text[], '{"note":"Set phrase = the sidelining/neglect of something cultural; built on ''soslayo'' (see soslayo). Used in critique and journalism.","collocations":["el soslayo cultural de","denunciar el soslayo"]}'::jsonb),
('c2-119', 'es', 'encomiable', 'praiseworthy, commendable', 'Realizó una labor encomiable durante la crisis.', 'C2'::cefr_level, 'Society', ARRAY['loable','meritorio'], '{"note":"Deserving of praise — effort, attitude, work; loable is synonymous, both formal. ''una labor encomiable''.","collocations":["una labor encomiable","un esfuerzo encomiable"]}'::jsonb),
('c2-120', 'es', 'loable', 'laudable, praiseworthy', 'Es loable su empeño por mejorar las cosas.', 'C2'::cefr_level, 'Society', ARRAY['encomiable','meritorio'], '{"note":"Praiseworthy — intentions, efforts; encomiable/meritorio are close. ''un empeño loable''.","collocations":["un empeño loable","una iniciativa loable"]}'::jsonb),
('c2-121', 'es', 'baladí', 'trivial, of little importance', 'No era un asunto baladí, sino crucial.', 'C2'::cefr_level, 'Society', ARRAY['trivial','insignificante'], '{"grammar":"invariable; pl. baladíes","note":"Trivial, of no importance — often negated for emphasis (''no es asunto baladí''). trivial/insignificante are close.","collocations":["un asunto baladí","no es baladí"]}'::jsonb),
('c2-122', 'es', 'inopinado', 'unexpected, unforeseen', 'Un giro inopinado cambió el rumbo de los hechos.', 'C2'::cefr_level, 'Society', ARRAY['inesperado','imprevisto'], '{"note":"Unexpected and unforeseen; inesperado/imprevisto are close, inopinado more literary. ''un giro inopinado''.","collocations":["un giro inopinado","de forma inopinada"]}'::jsonb),
